INSERT INTO papers (id, pmid, doi, title, abstract, year, source, metadata) VALUES
  ('c53857f7-115e-5d05-94d7-cd1f07a9c5cd', '41323807', '10.1016/j.bbrep.2025.102350', 'CdmR, a MarR family protein from &lt;i&gt;Clostridioides difficile&lt;/i&gt;, binds with positive cooperativity in the predicted promoter region of a MATE efflux transporter', '<i>Clostridioides difficile</i> is one of the most common causes of nosocomial infections worldwide and is responsible for a spectrum of conditions ranging from colitis to severe cases of sepsis, and even death. Of significant concern is the evolving antibiotic resistance of this pathogen, notably the recent emergence of strains with resistance to vancomycin and fidaxomicin, the first-line antibiotics currently used to treat <i>C. difficile</i> infections. Numerous members of the multiple antibiotic resistance regulator (MarR) protein family have been shown to play important roles in mediating drug-resistance in bacterial species, however very little is understood about their functions in <i>C. difficile</i>. Of the 14 MarR proteins predicted to be encoded in the <i>C. difficile</i> genome, only one has been functionally characterized to date, so the roles these proteins play in <i>C. difficile</i> pathogenicity are largely unknown. Here, we report the first biochemical study of the MarR homolog, CdmR, from <i>C. difficile</i>. CdmR binds with high sequence-specificity and high affinity at two DNA sites in the promoter region of an operon that encodes a predicted multidrug and toxic compound extrusion (MATE) family efflux transporter. The location of these sites strongly suggests that CdmR binding represses its own expression and that of the MATE gene. CdmR exhibits positive binding cooperativity at the two DNA sites, suggesting a highly sensitive and tightly controlled regulatory mechanism that may play an important role in the antibiotic resistance profile of <i>C. difficile</i>.', 2025, 'europepmc', '{"authorString": "Canepa J, Garcia-Ortiz R, Thompson K, Glidden J, Panchal B, Takahashi R, Kim DE, Wilkinson SP.", "journal": null}'::jsonb),
  ('ff14e0a1-546f-5419-9def-136479270c89', '41383968', '10.3389/fvets.2025.1697872', 'Resistance evolution under potentiated sulphonamide pressure in &lt;i&gt;Escherichia coli&lt;/i&gt;', '<h4>Introduction</h4>Antimicrobial resistance (AMR) poses an escalating global health threat. Potentiated sulphonamides are widely used in both veterinary and human medicine. This study aimed to investigate the <i>in vitro</i> adaptation of <i>Escherichia coli</i> strains to increasing concentrations of potentiated sulphonamides, focusing on co-selection and the genetic mechanisms of resistance.<h4>Methods</h4>The MEGA-plate evolutionary model was used to expose <i>E. coli</i> ATCC 25922 to increased concentrations (0 × to 1000×) of a potentiated sulphonamide. Clones isolated from different concentration zones were analyzed for phenotypic resistance via minimum inhibitory concentration (MIC) testing and genotypically through next-generation sequencing.<h4>Results</h4>In strains adapted to 1000 × potentiated sulphonamide, MIC values significantly increased for most tested antibiotics. Mutations were identified in key folate pathway genes (<i>folP</i>, <i>folA</i>), as well as in efflux pump regulator genes (<i>emrR</i>, <i>marR</i>, <i>acrR</i>, <i>mdtM</i>). These genetic changes indicated activation of multiple multidrug efflux systems, including <i>acrAB-tolC</i>, <i>emrAB-tolC</i>, and <i>mdtEF-tolC</i>. Mutations were also detected in genes associated with SOS response regulation (<i>recN</i>, <i>recQ</i>, <i>uvrB</i>), suggesting stress-induced genetic adaptation. <i>In vitro</i> microevolutionary adaptation to potentiated sulphonamide exposure induced broad genetic changes in <i>E. coli</i>, potentially driving cross-resistance through co-selection. The MEGA-plate method proved to be a robust tool for tracking resistance development and dissecting complex resistance mechanisms.<h4>Discussion</h4>These findings underscore the need for cautious use of combination antimicrobials, as they may elicit pleiotropic resistance responses beyond their intended targets.', 2025, 'europepmc', '{"authorString": "Kerek \u00c1, T\u00f6r\u00f6k B, Szab\u00f3 \u00c1, Laczk\u00f3 L, Kardos G, B\u00e1nyai K, Kaszab E, Bali K, Jerzsele \u00c1.", "journal": null}'::jsonb),
  ('499cb5db-b758-5651-9a56-2d5d22997550', '41943449', '10.1111/mpp.70255', 'The MarR Family Transcriptional Regulator EmrR Negatively Regulates the Type III Secretion System (T3SS) and Positively Modulates Pathogenicity in Dickeya oryzae', 'The pathogen Dickeya oryzae is responsible for soft rot disease in both monocotyledonous and dicotyledonous plants, resulting in substantial yield losses across a variety of important crops. However, the molecular mechanisms and signalling pathways that regulate bacterial virulence remain poorly understood. In this study, we identified a conserved transcriptional regulator, EmrR (multidrug efflux transporter EmrAB transcriptional repressor), in Dickeya species that plays a critical role in controlling cellular motility. Phenotypic analysis demonstrated that EmrR is also involved in the regulation of cellulase, as well as biofilm formation. emrRdeletion mutants displayed markedly decreased virulence in rice seed germination and potato tubes. Further investigation revealed that EmrR negatively regulates the expression of genes encoding the type III secretion system by decreasing the intracellular concentration of c-di-GMP (bis-(3''-5'')-cyclic dimeric guanosine monophosphate) and also modulates the key regulatory gene hrpL within this system. DNase I footprinting confirmed that EmrR binds specifically to a sequence (5''-CATTCGTTACTATGCAGGTTG-3'') in the emrR promoter region. This finding highlights EmrR as a conserved and essential regulator of virulence in Dickeya, providing novel insights into the complex signalling and regulatory networks that regulate physiological processes, biochemical mechanisms and virulence development in this pathogen.', 2026, 'europepmc', '{"authorString": "Lv M, Huang W, Meng Z, Fan X, Li P, Xu Z, Chen S, Chen X, Zhou J, Zhang L, Cheng Y, Zhuo T, Hu M.", "journal": null}'::jsonb),
  ('3630018a-114c-5314-b6ef-f070f5ca5fe5', '41644691', '10.1038/s41598-026-37272-w', 'Integrated analysis of global regulators and efflux genes associated with antimicrobial resistance reversal in multidrug resistant Klebsiella pneumoniae', '<h4>Background</h4>Multidrug-resistant Klebsiella pneumoniae poses a growing clinical challenge due to its ability to evade antibiotic treatment, particularly through the overexpression of efflux systems. Among these, the AcrAB-TolC pump is central to resistance against fluoroquinolones. While the global regulator''s MarA, SoxS, and Rob are known modulators of efflux in Enterobacteriaceae, their functional relevance in clinical K. pneumoniae remains insufficiently defined and largely correlation-based.<h4>Objective</h4>This study was designed to (1) determine the transcriptional association between the global regulators MarA, SoxS, and Rob with the AcrAB-TolC efflux system in multidrug-resistant (MDR) Klebsiella pneumoniae, and (2) functionally assess whether efflux contributes to fluoroquinolone resistance through PAβN-based inhibition assays. Together, these two analytical layers suggest a possible link between regulator expression and efflux-associated resistance reversal, without confirming direct regulatory activation.<h4>Methods</h4>Thirty clinical MDR isolates and ten susceptible controls were characterized via antibiotic susceptibility testing. Gene expression was quantified using qRT-PCR, normalized to 16S rRNA, and analyzed by the 2^-ΔΔCt method. Pearson correlation assessed relationships between gene expression and resistance. Phenotypic validation of efflux activity was performed using PAβN, an AcrAB-TolC inhibitor.<h4>Results</h4>MDR isolates exhibited significant overexpression of marA (5.0-fold), soxS (4.0-fold), acrB (7.9-fold), and other efflux components (p < 0.001). Strong positive correlations were observed between marA/soxS and acrB expression, suggesting a potential regulatory association. PAβN exposure reduced ciprofloxacin MICs by ≥ fourfold in 80% of high acrB expression isolates, supporting the involvement of active efflux mechanisms.<h4>Conclusion</h4>Our integrated findings indicate that higher marA/soxS expression is associated with increased gene expression of the AcrAB-TolC efflux pump and fluoroquinolone resistance in clinical MDR isolates, while PAβN-mediated efflux inhibition is associated with partial susceptibility restoration. Together, these results highlight global regulators and efflux pumps as actionable therapeutic targets for resistance reversal.', 2026, 'europepmc', '{"authorString": "Obaid AJ, Alkawaz AJ, Naser MS.", "journal": null}'::jsonb),
  ('8b37fc05-89dd-567a-accf-0a984020ca8d', '42106608', '10.1186/s12863-026-01421-x', 'Genomic and molecular characterisation of a KPC-producing Klebsiella pneumoniae clinical isolate resistant to meropenem-vaborbactam, imipenem-relebactam, and ceftazidime-avibactam', '<h4>Background</h4>Resistance to carbapenems and third-generation cephalosporins is increasing in Klebsiella pneumoniae globally, restricting therapeutic options. The β-lactam/β-lactamase inhibitor combinations are widely used to circumvent β-lactamase-mediated resistance. In 2021, an unusual K. pneumoniae clinical isolate, KpMVR1, was recovered from a hospitalised patient in England, exhibiting resistance to meropenem-vaborbactam, imipenem-relebactam, and ceftazidime-avibactam. To investigate this phenomenon, we characterised the genome and antimicrobial susceptibility of KpMVR1 alongside two clonally related isolates susceptible to all three β-lactam/β-lactamase inhibitor combinations: KpMVS1, collected from the same patient 42 days earlier, and KpMVS2, from another patient in the same hospital.<h4>Methods</h4>Illumina and MinION whole-genome sequencing were conducted for these three isolates, followed by hybrid genome assembly. Annotated genome assemblies were compared to identify genetic variation. Mutagenesis experiments were performed to verify predicted functional alterations.<h4>Results</h4>All isolates belonged to clone ST8134 and carried bla<sub>KPC-2</sub> alleles (KpMVR1: bla<sub>KPC-157</sub>; KpMVS1 and KpMVS2: bla<sub>KPC-2</sub>) in plasmids predicted to be conjugative. Insertion sequence ISEc68 caused a frameshift mutation in KpMVR1''s ompK36 gene, reducing susceptibility to meropenem-vaborbactam and imipenem-relebactam. KPC-157 demonstrated decreased hydrolysis of imipenem and ceftazidime when compared with KPC-2. KpMVR1 also encoded a disrupted transcriptional repressor MarR and a destabilising mutation in AcrB, a component of the AcrAB-TolC multidrug efflux pump. An intact, iron-transporting fec operon was identified on a novel IncFII(pKP91)/IncFIB(K) plasmid unique to KpMVS2, possibly accounting for the cefiderocol resistance observed in this isolate.<h4>Conclusions</h4>KpMVR1 carried multiple resistance-associated genetic alterations and likely developed its resistance profile through within-patient evolution. This study highlights the importance of routine screening for resistant pathogens in vulnerable patients to guide antimicrobial chemotherapy and the need to characterise underlying resistance mechanisms to assess the risk of onward dissemination.', 2026, 'europepmc', '{"authorString": "Wan Y, Wong JLC, Sanchez-Garrido J, Low WW, Turton JF, Morecchiato F, Baccani I, Dodgson K, Rossolini GM, Woodford N, Frankel G, Jauneikaite E, Meunier D, Hopkins KL.", "journal": null}'::jsonb),
  ('2d1feffa-8d8e-5f51-b4e7-0eacf9cb294a', '41822337', '10.3389/fcimb.2026.1745642', 'Effect of sub-inhibitory tigecycline (½-MIC) on AcrAB-TolC and &lt;i&gt;mar/ram/sox&lt;/i&gt; regulatory genes in &lt;i&gt;Enterobacter cloacae&lt;/i&gt; complex isolates', 'The global rise of antimicrobial resistance (AMR) in <i>Enterobacterales</i>, including the <i>Enterobacter cloacae</i> complex, is narrowing treatment options. Tigecycline, a last-resort antibiotic for the treatment of multidrug-resistant (MDR) Gram-negative pathogens, is increasingly compromised by emerging resistance mechanisms, notably efflux pump overexpression and regulatory network adaptation. In this study, sixty clinical isolates of <i>Enterobacter cloacae</i> (thirty-eight tigecycline-resistant [TGC-R], twenty-two tigecycline-susceptible [TGC-S]) were analyzed to investigate gene expression changes in efflux pumps and regulatory genes under tigecycline pressure (1/2 minimum inhibitory concentration [MIC]) and standard conditions. Tigecycline exposure markedly increased <i>tolC</i> and <i>acrA</i> together with the regulators <i>marA</i> and <i>ramA</i>, while <i>acrB</i> increased only modestly. This indicates a strong regulatory component to the tigecycline response. In contrast, TGC-S isolates exhibited significant induction of <i>marA, marB</i> without corresponding activation of efflux pumps. Δlog<sub>2</sub>FC analysis highlighted distinct transcriptional shifts between exposed and unexposed groups, with resistant strains displaying greater divergence. Heatmaps and boxplot visualizations, supported by Wilcoxon test statistics, underscored the regulatory responses associated with tigecycline pressure. These findings indicate that, alongside AcrAB-TolC upregulation, stress-responsive regulators (<i>marA</i>, <i>ramA</i>) are strongly induced by sub-inhibitory tigecycline, underscoring the multifactorial regulation of tigecycline response in the <i>E</i>. <i>cloacae</i> complex.', 2026, 'europepmc', '{"authorString": "Korczak L, Majewski P, Sacha P, Chludzinska D, Tryniszewska E.", "journal": null}'::jsonb),
  ('51be1dda-2772-5990-a2ac-f0b98b0c7ee3', '40855113', '10.1038/s44259-025-00144-w', 'The effect of commonly used non-antibiotic medications on antimicrobial resistance development in Escherichia coli', 'Antimicrobial resistance (AMR) poses a global threat to public health. While antibiotic overuse is a primary driver, emerging evidence suggests that non-antibiotic medications (NAMs) may also contribute. This concern is particularly relevant in residential aged care facilities (RACFs), where both NAMs and antibiotics are frequently used. We investigated whether nine commonly used NAMs in RACFs, including ibuprofen, diclofenac, acetaminophen, furosemide, metformin, atorvastatin, tramadol, temazepam, and pseudoephedrine at gut-relevant concentrations, enhance ciprofloxacin-induced mutagenesis in Escherichia coli. Our findings showed that ibuprofen and acetaminophen significantly increased mutation frequency and conferred high-level ciprofloxacin resistance. Whole-genome sequencing identified mutations in GyrA, MarR, and AcrR, with the latter two correlated with overexpression of AcrAB-TolC drug efflux pump. Co-exposure to two NAMs further elevated mutation rates and ciprofloxacin resistance levels. This study underscored the overlooked role of NAMs in driving AMR and highlighted the need to reassess polypharmacy risks in aged care settings.', 2025, 'europepmc', '{"authorString": "Chen H, Sapula SA, Turnidge J, Venter H.", "journal": null}'::jsonb),
  ('42f2d384-90a6-559f-b5ad-96de183bc3cc', '41900353', '10.3390/microorganisms14030593', 'Genotypic and Phenotypic Characterization of &lt;i&gt;Cronobacter&lt;/i&gt; spp. Strains Isolated from Powdered Milk Formulas and Dairy Production Environments', '<i>Cronobacter</i> spp. is a pathogenic genus comprising seven species, of which <i>C. sakazakii</i> is particularly notable for its association with neonatal outbreaks linked to powdered infant formula. The severity of infections is associated with virulence factors (VFs) and β-lactam antibiotic resistance genes (ARGs). Next-generation sequencing (NGS) has enabled precise strain typing through core genome multilocus sequence typing (cgMLST), enhancing discrimination and accuracy. This study aimed to use cgMLST (2831 genes) to genomically characterize 34 <i>Cronobacter</i> strains which had been isolated from powdered milk and production surfaces between 2011 and 2022. The identified strains included <i>C. sakazakii</i> ST1, ST4, ST13, ST31 and ST83, as well as <i>C. malonaticus</i> ST60. Overall, there were eight clusters of closely related strains. All strains exhibited resistance to cephalothin, 18 were resistant to ceftazidime and 11 to ampicillin. Various resistance genes (<i>bla<sub>CSA</sub></i>, <i>bla<sub>CMA</sub></i>, <i>fos</i>, <i>qacJ</i>, <i>marA</i>, <i>AcrAB-TolC</i>, and <i>mcr-9</i>.<i>1</i>) and virulence genes (<i>cpa</i>, <i>nanAKT</i>, <i>fic</i>, <i>relB</i>, <i>fliC</i>) were detected, with some genes being exclusive to <i>C. sakazakii</i>. All strains carried plasmids and mobile genetic elements. The multidrug resistance and presence of virulence genes in these isolates highlight the significant risk that <i>C. sakazakii</i>-contaminated powdered dairy products pose to public health, underscoring the need to adopt proper hygienic manufacturing practices and effectively implement HACCP in their production.', 2026, 'europepmc', '{"authorString": "Parra-Flores J, Daza-Prieto B, Troncoso M, Figueroa G, Reyes-Fuentes MI, Holy O, Cruz-C\u00f3rdova A, Ruppitsch W, Forsythe S.", "journal": null}'::jsonb),
  ('5863d017-1f3d-5d81-b0b7-adcc4224c715', '42089625', '10.1128/jb.00502-25', 'The MarR family regulator RmaH underlies the trade-off between acid sensitivity and antibiotic tolerance in &lt;i&gt;Lactococcus lactis&lt;/i&gt;', 'Microorganisms exhibit remarkable adaptability to diverse environmental stresses through transcriptional reprogramming. Here, we focused on the MarR family regulator RmaH in <i>Lactococcus lactis</i>, which orchestrated a pivotal trade-off: enhancing tolerance to the bacteriocin nisin and the antibiotic vancomycin at the expense of acid resistance. RmaH directly activated genes for cell wall and membrane lipid biosynthesis, leading to a thicker cell wall, and repressed the arginine deiminase pathway, attenuating acid tolerance. Integrated transcriptomic, chromatin immunoprecipitation-sequencing, and electrophoretic mobility shift assay identified RmaH as a global transcription regulator, modulating processes, including amino acid transport and metabolism, cell wall/membrane/envelope biogenesis, carbohydrate transport and metabolism, and nucleotide transport and metabolism. The molecular basis of this regulation was defined by identifying two RmaH-specific DNA-binding motifs and confirming the essential role of arginine residues R79 and R87 in DNA binding. Our work elucidated a sophisticated regulatory mechanism that enabled bacteria to navigate complex and changing stressors.<h4>Importance</h4>This study reveals how the global regulator RmaH in <i>Lactococcus lactis</i> orchestrates a critical survival trade-off, prioritizing antibiotic tolerance over acid resistance. By directly activating cell wall and membrane biosynthesis pathways, RmaH enhances defense against antimicrobials like nisin and vancomycin. Concurrently, it represses the arginine deiminase pathway, compromising the cell''s ability to mitigate acid stress. This work provides a fundamental model for how bacteria dynamically allocate finite cellular resources to navigate complex, changing environments. The elucidated mechanism offers broader insights into bacterial persistence strategies and the physiological compromises underlying stress response networks.', 2026, 'europepmc', '{"authorString": "Song Q, Zhang P, Wu H, Zhu H, Liu J, Qiao J.", "journal": null}'::jsonb),
  ('41712c64-b205-5060-9781-3e66187c44df', '42075314', '10.3390/microorganisms14040920', 'Functional Identification of AcsR, a MarR Family Transcriptional Regulator Involved in the Regulation of Aromatic Compound-Degrading Genes in &lt;i&gt;Corynebacterium glutamicum&lt;/i&gt;', 'The MarR (multiple antibiotic resistance regulator) family regulators, which are widely conserved across various organisms, play pivotal roles in metabolism, stress response mechanisms, and virulence factor production. However, the regulatory functions of these factors in the degradation of aromatic compounds within <i>Corynebacterium glutamicum</i> remain largely uncharacterized. In this study, we identified a MarR-type regulator, designated AcsR (encoded by <i>ncgl2425</i>), which directly represses the expression of the catechol 2,3-dioxygenase gene <i>ncgl2007</i> (<i>c23o</i>) and the heavy metal (nickel) transport system permease gene <i>ncgl2351</i>, while activating the expression of <i>ncgl2258</i> encoding an ABC-type C4-dicarboxylate-binding periplasmic protein. AcsR binds specifically as a dimer to a 6 bp inverted repeat sequence, and this binding is disrupted by catechol in vitro. Correspondingly, catechol induces the expression of <i>c23o</i> in vivo. Phenotypic analysis revealed that the Δ<i>acsR</i> mutant exhibited enhanced resistance to multiple aromatic compounds but increased sensitivity to antibiotics, heavy metals, and oxidants. Collectively, these findings demonstrate that AcsR is an important regulator of stress adaptation in <i>C. glutamicum</i> and provide new insights into the regulatory mechanisms of aromatic compound degradation in this industrially important bacterium.', 2026, 'europepmc', '{"authorString": "Shi Q, Xu R, Shao M, Wang S, Wang R, Liu J, Li X, Wang R, Zou T, Yang M, Si M, Chen C.", "journal": null}'::jsonb),
  ('7a10437c-311f-543d-aeb6-523e363f9430', '41594107', '10.3390/antibiotics15010070', 'Impact of the Transcriptional Regulator SCO7424 Overexpression on Antibiotic Production in <i>Streptomyces coelicolor</i>', '<b>Background.</b> The genus <i>Streptomyces</i> is known for its capability to produce a wide range of bioactive secondary metabolites. The enzymes required for their synthesis are encoded within biosynthetic gene clusters (BGCs), whose expression can be influenced by various physical and nutritional factors. Among these nutritional factors, it is worth highlighting carbon catabolic repression (CCR), which prevents the formation of secondary metabolites. It has been shown that transcriptional factors, in turn, regulated by glucose or by the enzyme glucose kinase (Glk), may be involved in this mechanism. It was shown that the expression of some transcriptional factors is regulated by glucose availability and that the enzyme glucose kinase (Glk) may play a role in this process. One of the transcriptional factors most upregulated in the presence of glucose/agar in <i>Streptomyces coelicolor</i> M145 is SCO7424, a member of the MarR family of transcriptional regulators. However, its influence on antibiotic synthesis has never been studied. <b>Objective.</b> In this work, we evaluated the effect of SCO7424 overexpression on the synthesis of actinorhodin (ACT) and undecylprodigiosin (RED), and its impact on growth and glucose consumption. <b>Methods.</b> A copy of the <i>sco7424</i> gene was cloned into the pIJ702 plasmid, which was then transformed into a wild-type strain of <i>S. coelicolor</i> M145. Growth and antibiotic production were evaluated in the strain with two copies of <i>sco7424</i> and in the wild-type strain. We also evaluated the expression of the probable target genes by quantitative RT-PCR. <b>Results</b>. We found that overexpression of <i>sco7424</i> negatively impacts growth, glucose consumption kinetics, and the expression of specific regulators of the ACT and RED biosynthetic pathways, resulting in reduced ACT and RED production. Understanding the function of the regulatory cascades regulated by this family of regulators is crucial for boosting the yields of valuable metabolites produced by industrial strains.', 2026, 'europepmc', '{"authorString": "Vega-Sauceda G, Villarreal-G\u00f3mez K, Ruiz-Villaf\u00e1n B, Rodr\u00edguez-Sanoja R, S\u00e1nchez S.", "journal": null}'::jsonb),
  ('013964fe-a47f-5fcd-9ab7-9b3954c77c2b', '41868357', '10.3389/fmicb.2026.1727573', '&lt;i&gt;Mycobacterium tuberculosis&lt;/i&gt; MarR family transcription factor Rv0737 regulates bacterial growth and lipid synthesis by targeting the sigL-rslA operon', 'The MarR family of transcription factors in <i>Mycobacterium tuberculosis</i> plays a critical role in bacterial adaptation to host stresses, yet the function of many members remains unknown. Here, we characterize the novel MarR regulator Rv0737 and its homolog Ms_1492 in <i>M. smegmatis</i>. Overexpression of Rv0737 severely impaired bacterial growth, cell division, and biofilm formation, while increasing susceptibility to oxidative stress and the cell wall-targeting drug isoniazid. Conversely, deletion of <i>ms_1492</i> altered cell envelope permeability and lipid composition, enhanced ATP synthesis, and conferred mild tolerance to H<sub>2</sub>O<sub>2</sub> and isoniazid. Lipid profiling and transcriptomic analysis revealed significant dysregulation of lipid metabolism genes. Crucially, electrophoretic mobility shift assays demonstrated that both Rv0737 and Ms_1492 directly bind to the promoter region of the sigL-rslA operon, which encodes an alternative sigma factor and its anti-sigma factor. Our findings establish a direct regulatory pathway wherein Rv0737/Ms_1492 modulates bacterial growth, cell envelope integrity, and stress response by targeting the sigL-rslA operon, identifying this system as a potential therapeutic target for combating drug-resistant tuberculosis.', 2026, 'europepmc', '{"authorString": "Abudukadier A, Zhang Q, Li G, Chen H, Li P, Gong Z, Xie J.", "journal": null}'::jsonb),
  ('8b2b9e92-f877-5639-b29f-2a03a929202f', '41334941', '10.1021/acs.biochem.5c00617', 'DNA Distortion by the &lt;i&gt;Burkholderia thailandensis&lt;/i&gt; Transcriptional Regulator FusR2 Is Abolished by Fusaric Acid Binding', 'Fusaric acid is a toxic metabolite produced by several <i>Fusarium</i> species, which causes wilt disease in many plants. Among other functions, fusaric acid allows the fungus to outcompete soil bacteria. Understanding mechanisms by which bacteria mitigate the toxic effects of fusaric acid is therefore of interest in terms of controlling Fusarium wilt. The soil bacterium <i>Burkholderia thailandensis</i> encodes a predicted fusaric acid-binding membrane transporter belonging to the FusC2 family. The <i>fusC2</i> gene is annotated as part of an operon, also encoding an isochorismatase (gene named <i>isoC</i>) and a member of the multiple antibiotic resistance (MarR) family of transcription factors. Isochorismatase converts isochorismate to the antifungal compound 2,3-dihydroxybenzoate. We show here that the transcription factor, which we named FusR2, binds specifically to the promoter of the <i>fusR2-isoC-fusC2</i> operon and that FusR2 induces marked changes in DNA conformation, as evidenced by hypersensitive DNase I cleavage sites. Fusaric acid induces the expression of <i>fusR2-isoC-fusC2</i>, and it binds directly to FusR2, as shown by thermal shift assays. While the presence of fusaric acid is compatible with DNA binding by FusR2, it eliminates the hypersensitive DNA cleavage. We propose that FusR2 imposes a DNA conformation, which adversely affects the ability of RNA polymerase to bind, whereas fusaric acid binding to FusR2 results in an altered DNA binding mode, in which the RNA polymerase can compete with FusR2 for DNA binding to initiate transcription. By this mechanism, fusaric acid induces the expression of genes encoding both an efflux pump and an enzyme involved in the production of an antifungal metabolite.', 2025, 'europepmc', '{"authorString": "Nwokocha GC, Bhattacharyya N, LeBoeuf EN, Elkholy H, Grove A.", "journal": null}'::jsonb),
  ('550aa3c9-da68-5941-b19a-635b4f6a4220', '41123208', '10.1093/nar/gkaf1032', 'DNA-bound structure of Clostridioides difficile heme-sensing HsmR gives insight on how the unique dimer mode governs DNA specificity in MarR transcriptional regulators', 'Clostridioides difficile is a pathogenic bacterium responsible for illnesses ranging from diarrhea to life-threatening colitis and has emerged as a significant public health concern due to its resistance to antibiotics. During its infection, intestinal bleeding causes lysis of the red blood cells releasing heme, a toxic oxidant for the bacterium. To counteract, HsmR of the MarR family transcriptional regulator senses the heme and induces the expression of HsmA to sequester the heme. The structure of HsmR in complex with its cognate pseudo-palindromic DNA illustrates that the lysine and arginine of the winged helix-turn-helix motif undergo conformational changes to accommodate the DNA, and to interact with specific DNA bases. However, conservation of these residues in half of 14 or so C. difficile MarRs within its genome raises a question on how specificity between MarR and DNA is achieved. Comparisons of various C. difficile MarR structures suggest that they probably have acquired DNA selectivity by the slightly different dimeric mode mediated by mutual interaction between the first helices of each HsmR subunit. The unique HsmR dimer mode allows symmetric recognition toward its own cognate DNA, and heme binding would happen in concert with reorientation of these helices in turn affecting DNA binding.', 2025, 'europepmc', '{"authorString": "Rho S, Kwon N, Park S.", "journal": null}'::jsonb),
  ('57756b8c-59ba-53df-8770-1551af392dec', '40852986', '10.1128/mbio.01396-25', 'The MarR family transcription factor SlyA senses iron and respiratory status in enteric bacteria', 'SlyA and its homologs are conserved transcription factors in enteric bacteria, including <i>Salmonella enterica</i>, in which it upregulates horizontally acquired virulence genes. SlyA is a member of the MarR family of transcription factors, which possess a small molecule binding pocket. Ligand binding causes the protein to undergo a conformational change that abrogates DNA binding. Although the original discovery of MarR was based on its ability to recognize xenobiotic compounds and promote their efflux, the conservation of MarR family members throughout Bacteria and Archaea suggests a more general function. Because SlyA is known to bind xenobiotic aromatic carboxylates, we performed a targeted analysis of aromatic metabolic genes in <i>Salmonella</i> Typhimurium to identify potential endogenous ligands. We found that SlyA is promiscuously inhibited by multiple aromatic carboxylates including 2,3-dihydroxybenzoate, a precursor of iron-scavenging catecholate siderophores, and 4-hydroxybenzoate, a precursor of quinone-based electron-carriers, which allows it to sense changes in iron availability, respiration, and growth on succinate. We suggest that SlyA and other MarR proteins sense metabolic status via the flux of aromatic carboxylates in biosynthetic pathways. This allows SlyA to function as a counter-silencer of horizontally acquired genes that is exquisitely responsive to the metabolic state of the cell.IMPORTANCEMarR proteins comprise an ancient group of transcription factors that emerged before the divergence of Archaea and Bacteria. First identified as regulators of antibiotic efflux, they have also been suggested to sense and regulate concentrations of endogenous intracellular metabolites, but such metabolites have not previously been identified. Here we show that SlyA, a conserved and essential MarR family virulence gene regulator in enteric pathogens, binds to and is inhibited by aromatic metabolites required for many essential cellular processes. Our findings show how SlyA integrates metabolic status into bacterial transcriptional networks that control both molecular efflux and virulence.', 2025, 'europepmc', '{"authorString": "Will WR, Fang FC.", "journal": null}'::jsonb),
  ('49e9208c-ba6e-5163-a36d-a3cbc2c88c8c', '40868036', '10.3390/antibiotics14080841', 'Deciphering Common Genetic Pathways to Antibiotic Resistance in &lt;i&gt;Escherichia coli&lt;/i&gt; Using a MEGA-Plate Evolution System', '<b>Background.</b> Antimicrobial resistance (AMR) poses a significant global health threat, necessitating a deeper understanding of bacterial adaptation mechanisms. <b>Introduction.</b> This study investigates the genotypic and phenotypic evolutionary trajectories of <i>Escherichia coli</i> under meropenem and gentamicin selection, and it benchmarks these findings against florfenicol-evolved strains. <b>Methodology.</b> Utilizing a downsized, three-layer acrylic modified "Microbial Evolution and Growth Arena (MEGA-plate) system"-scaled to 40 × 50 cm for sterile handling and uniform 37 °C incubation-we tracked adaptation over 9-13 days, enabling real-time visualization of movement across antibiotic gradients. <b>Results.</b> Meropenem exposure elicited pronounced genetic heterogeneity and morphological remodeling (filamentous and circular forms), characteristic of SOS-mediated division arrest and DNA-damage response. In contrast, gentamicin exposure produced a uniform resistance gene profile and minimal shape changes, suggesting reliance on conserved defenses without major morphological adaptation. Comprehensive genomic analysis revealed a core resistome of 22 chromosomal loci shared across all three antibiotics, highlighting potential cross-resistance and the central roles of <i>baeR</i>, <i>gadX</i>, and <i>marA</i> in coordinating adaptive responses. Gene ontology enrichment underscored the positive regulation of gene expression and intracellular signaling as key themes in resistance evolution. <b>Discussion.</b> Our findings illustrate the multifaceted strategies <i>E. coli</i> employs-combining metabolic flexibility with sophisticated regulatory networks-to withstand diverse antibiotic pressures. This study underscores the utility of the MEGA-plate system in dissecting spatiotemporal AMR dynamics in a controlled yet ecologically relevant context. <b>Conclusions.</b> The divergent responses to meropenem and gentamicin highlight the complexity of resistance development and reinforce the need for integrated, One Health strategies. Targeting shared regulatory hubs may open new avenues for antimicrobial intervention and help preserve the efficacy of existing drugs.', 2025, 'europepmc', '{"authorString": "Morales-Dur\u00e1n N, Le\u00f3n-Buitimea A, \u00c1lvarez Mart\u00ednez R, Morones-Ram\u00edrez JR.", "journal": null}'::jsonb),
  ('e05c36ef-4822-5c90-9497-60db0b772761', '41474324', '10.1128/mbio.03292-25', 'Structural basis of quinone sensing by the MarR-type repressor MhqR in &lt;i&gt;Staphylococcus aureus&lt;/i&gt;', 'The MarR-family regulator MhqR of <i>Staphylococcus aureus</i> (<i>Sa</i>MhqR) was previously characterized as a quinone-sensing repressor of the <i>mhqRED</i> operon. Here, we solved the crystal structures of apo-<i>Sa</i>MhqR and the 2-methylbenzoquinone (MBQ)-bound <i>Sa</i>MhqR complex. AlphaFold3 modeling was used to predict the structure of <i>Sa</i>MhqR in complex with its operator DNA. In the DNA-bound <i>Sa</i>MhqR state, S65 and S66 of an allosteric α3-α4 loop adopted a helically wound conformation to elongate helix α4 for optimal DNA binding. Key residues for MBQ interaction were identified as F11, F39, E43, and H111, forming the MBQ-binding pocket. MBQ binding prevented the formation of the extended helix α4 in the allosteric loop, leading to steric clashes with the DNA. Molecular dynamics (MD) simulations revealed an increased intrinsic dynamics within the allosteric loop and the β1/β2-wing regions after MBQ binding to prevent DNA binding. Using mutational analyses, we validated that F11, F39, and H111 are required for quinone sensing <i>in vivo,</i> whereas S65 and S66 of the allosteric loop and D88, K89, V91, and Y92 of the β1/β2-wing are essential for DNA binding <i>in vitro</i> and <i>in vivo</i>. In conclusion, our structure-guided modeling and mutational analyses identified a quinone-binding pocket in <i>Sa</i>MhqR and the mechanism of <i>Sa</i>MhqR inactivation, which involves local structural rearrangements of an allosteric loop and high intrinsic dynamics to prevent DNA interactions. Our results provide novel insights into the redox mechanism of the conserved <i>Sa</i>MhqR repressor, which functions as an important determinant of quinone and antimicrobial resistance in <i>S. aureus</i>.IMPORTANCE<i>Staphylococcus aureus</i> is a major human pathogen that can cause life-threatening infections in humans. However, treatment options are limited due to the prevalence of antimicrobial-resistant isolates in the hospital and the community. The MarR-type repressor <i>Sa</i>MhqR was described to control resistance toward quinones and quinone-like antimicrobials. However, the redox-regulatory mechanism of <i>Sa</i>MhqR by quinones was unknown. In this work, we explored the DNA-binding and quinone-sensing mechanism of <i>Sa</i>MhqR and identified a quinone-binding pocket and an allosteric loop, which facilitates DNA binding activity via a helical wound conformation and adapts an unstructured coiled conformation upon quinone binding to inhibit DNA binding. A similar mechanism has been recently discovered for the regulation of uric acid resistance by UrtR family repressors (W. S. Song, D. U. Ki , H. Y. Cho, O. H. Kwon, H. Cho, S. I. Yoon, Nucleic Acids Res 52:13192-13205, 2024, https://doi.org/10.1093/nar/gkae922). Our results contribute to a better understanding of antimicrobial resistance regulation, which may be exploited for future drug design to combat multidrug-resistant <i>S. aureus</i>.', 2026, 'europepmc', '{"authorString": "Nguyen TT-P, Weiland P, Loi VV, Kiontke S, Burchert F, Zegarra V, Kern A, Fritsch VN, Baranov D, Bronowska AK, Bange G, Antelmann H.", "journal": null}'::jsonb),
  ('94582419-d92c-5afa-b0d9-446ac6d47d72', '41140411', '10.3389/fmicb.2025.1683709', 'Stress-resistant but phage-sensitive host mutants induced by phage T4 ghost adsorption', 'The main effect of lytic phages on the host is cell lysis, and genetic impact of short-term contact between the host and the phage remains unknown unless genetic exchange occurs. In this study, we found that the adsorption of a lytic phage to the host cell can rapidly alter the genetic and physiological properties of hosts that have escaped lysis without relying on gene transfer. After adsorption of the lytic phage T4 to <i>Escherichia coli</i> (host) cells, 1% of <i>E. coli</i> cells exhibited an approximately 85-fold increase in spontaneous mutant frequency, which was measured based on antibiotic resistance. Phage ghosts increased the incidence of mutator strains exhibiting elevated expression of the error-prone DNA polymerase IV gene (<i>dinB</i>), while the emergence of mutators was suppressed in the <i>dinB</i>-deficient strain. Adsorption of ghosts onto the cell surface triggered global changes in gene expression in surviving cells, including upregulation of DNA polymerase IV. This upregulation led to mutations in host genes such as <i>tfaR</i> and <i>marR</i>, which were associated with high mutant frequency. Phage- or ghost-derived mutator strains showed a higher frequency of resistance to reactive oxygen species and acid stresses than the parental strain but a lower frequency of resistance to phage T4. These findings suggested that phage ghosts may promote host cell survival and alter their physiological characteristics, thus contributing to the production of progeny virions in future phage attacks.', 2025, 'europepmc', '{"authorString": "Kenzaka T, Tani K.", "journal": null}'::jsonb),
  ('d96eeda5-2d16-51e6-9b4e-72ae0330cb1c', '39359673', '10.1002/mlf2.12140', 'The phytopathogen <i>Xanthomonas campestris</i> senses and effluxes salicylic acid via a sensor HepR and an RND family efflux pump to promote virulence in host plants', 'Salicylic acid (SA) plays an essential role in plant defense against biotrophic and semi-biotrophic pathogens. Following pathogen recognition, SA biosynthesis dramatically increases at the infection site of the host plant. The manner in which pathogens sense and tolerate the onslaught of SA stress to survive in the plant following infection remains to be understood. The objective of this work was to determine how the model phytopathogen <i>Xanthomonas campestris</i> pv. <i>campestris</i> (Xcc) senses and effluxes SA during infection inside host plants. First, RNA-Seq analysis identified an SA-responsive operon Xcc4167-Xcc4171, encoding a MarR family transcription factor HepR and an RND (resistance-nodulation-cell division) family efflux pump HepABCD in Xcc. Electrophoretic mobility shift assays and DNase I footprint analysis revealed that HepR negatively regulated <i>hepABCD</i> expression by specifically binding to an AT-rich region of the promoter of the <i>hepRABCD</i> operon, P<sub>hep</sub>. Second, isothermal titration calorimetry and further genetic analysis suggest that HepR is a novel SA sensor. SA binding released HepR from its cognate promoter P<sub>hep</sub> and then induced the expression of <i>hepABCD</i>. Third, the RND family efflux pump HepABCD was responsible for SA efflux. The <i>hepRABCD</i> cluster was also involved in the regulation of culture pH and quorum sensing signal diffusible signaling factor turnover. Finally, the <i>hepRABCD</i> cluster was transcribed during the XC1 infection of Chinese radish and was required for the full virulence of Xcc in Chinese radish and cabbage. These findings suggest that the ability of Xcc to co-opt the plant defense signal SA to activate the multidrug efflux pump may have evolved to ensure Xcc survival and virulence in susceptible host plants.', 2024, 'europepmc', '{"authorString": "Song K, Li R, Cui Y, Chen B, Zhou L, Han W, Jiang BL, He YW.", "journal": null}'::jsonb),
  ('d41ead6a-4c90-5f47-b974-92b4ce12ea70', '42045670', '10.1007/s00253-026-13831-z', 'Mitigating protocatechuic acid toxicity in Vibrio natriegens enables poly-3-hydroxybutyrate production from an aromatic carbon source', '3,4-Dihydroxybenzoic acid (protocatechuic acid, PCA) is a central intermediate in bacterial aromatic catabolism - a key node for processing aromatic waste streams such as lignin and polyethylene terephthalate (PET) and a compound of growing biotechnological interest for valorising complex aromatic feedstocks. Here, we present a proof-of-concept for upcycling of PCA as a sole carbon source into a non-aromatic, higher-value bioproduct. We show that Vibrio natriegens, an emerging microbial chassis, can use PCA to produce poly-3-hydroxybutyrate (PHB), with no additional carbon source such as yeast extract or peptone. Efficient growth on PCA required careful optimisation of substrate concentration, cultivation conditions, and medium composition, e.g. replacing Fe<sup>2</sup>⁺ with Fe<sup>3</sup>⁺. These strategies reduced PCA autoxidation and limited reactive oxygen species (ROS) toxicity. Adaptive laboratory evolution over ~ 1000 generations identified convergent mutations that reveal insights into the architecture of the oxidative stress response in V. natriegens, including catalytic enzymes such as a Dyp-type peroxidase, and multiple regulatory proteins including OxyR, MarR, RpoS, ToxS, and RseB. Further mutations implicate cell wall repair and protein quality control in the PCA stress response. Functionally, the adapted strains produced 2.5-fold more PHB in 80% of the time required by the parental strain. Overall, we demonstrate the potential and current limitations of V. natriegens for the sustainable upcycling of aromatic, waste-derived carbon into value-added bioproducts.', 2026, 'europepmc', '{"authorString": "Faber A, Politan R, Nicol A, Della Valle S, Jenkins B, Flematti G, Fritz G.", "journal": null}'::jsonb),
  ('40ef0846-f09f-5c90-ba0d-123b52833267', '38948149', '10.1002/mlf2.12109', 'MarR family proteins sense sulfane sulfur in bacteria', 'Members of the multiple antibiotic resistance regulator (MarR) protein family are ubiquitous in bacteria and play critical roles in regulating cellular metabolism and antibiotic resistance. MarR family proteins function as repressors, and their interactions with modulators induce the expression of controlled genes. The previously characterized modulators are insufficient to explain the activities of certain MarR family proteins. However, recently, several MarR family proteins have been reported to sense sulfane sulfur, including zero-valent sulfur, persulfide (R-SSH), and polysulfide (R-SnH, <i>n</i> ≥ 2). Sulfane sulfur is a common cellular component in bacteria whose levels vary during bacterial growth. The changing levels of sulfane sulfur affect the expression of many MarR-controlled genes. Sulfane sulfur reacts with the cysteine thiols of MarR family proteins, causing the formation of protein thiol persulfide, disulfide bonds, and other modifications. Several MarR family proteins that respond to reactive oxygen species (ROS) also sense sulfane sulfur, as both sulfane sulfur and ROS induce the formation of disulfide bonds. This review focused on MarR family proteins that sense sulfane sulfur. However, the sensing mechanisms reviewed here may also apply to other proteins that detect sulfane sulfur, which is emerging as a modulator of gene regulation.', 2024, 'europepmc', '{"authorString": "Xuan G, Xun L, Xia Y.", "journal": null}'::jsonb),
  ('40e7a689-380d-51bc-8d08-d014a3bdd7f2', '40772721', '10.1128/mbio.01369-25', 'Redox control of antibiotic biosynthesis', '<i>Streptomyces</i> bacteria make diverse specialized metabolites that form the basis of ~55% of clinically used antibiotics. Despite this, only 3% of their encoded specialized metabolites have been matched to molecules, and understanding how their biosynthesis is controlled is essential to fully exploit their potential. Here, we use <i>Streptomyces formicae</i> and the formicamycin biosynthetic pathway as a model to understand the complex regulation of specialized metabolism. We analyzed all three pathway-specific regulators and found that biosynthesis is subject to negative feedback and redox control via two MarR-family proteins, while activation of the pathway is dependent on a cytoplasmic two-component system. Like many <i>Streptomyces</i> antibiotics, formicamycins are only produced in solid culture, and biosynthesis is switched off in aerated liquid cultures. Here, we demonstrate that a redox-sensitive repressor named ForJ senses oxygen via a single cysteine residue that is required to repress formicamycin biosynthesis in liquid cultures.IMPORTANCEAntimicrobial resistance presents a significant threat to human health. <i>Streptomyces</i> bacteria are a promising source of novel antimicrobials; however, encouraging production of these molecules under laboratory conditions remains a challenge because we have limited understanding of the signals that control their production. Here, we use the formicamycin producer, <i>Streptomyces formicae</i>, as a model to further understand how antibiotic production is regulated in response to various signals. We show that three regulatory elements work together to coordinate formicamycin biosynthesis in response to intracellular signals, redox stress, and formicamycin accumulation. We also show that by making the regulators "blind" to these signals, we can induce high-level production of formicamycins in industrially relevant conditions, which facilitates their development as new antimicrobials.', 2025, 'europepmc', '{"authorString": "Devine R, Noble K, Stevenson C, Martins CdO, Saalbach G, McDonald HP, Hems ES, Wilkinson B, Hutchings MI.", "journal": null}'::jsonb),
  ('0aa9df53-4bcf-54fa-b5e4-c74e556f3e66', '39484741', '10.1093/nar/gkae922', 'Structural basis of transcriptional regulation by UrtR in response to uric acid', 'Uric acid (UA)-responsive transcriptional regulators (UrtRs), which belong to the multiple antibiotic resistance regulator (MarR) superfamily, transcriptionally coordinate virulence and metabolism in bacteria by modulating interactions with operator DNA in response to UA. To elucidate the transcriptional regulatory mechanism of UrtR, we structurally analyzed UrtR proteins, including PecS, MftR, and HucR, alone and in complex with UA or DNA. UrtR contains a dimerization domain (DD) and a winged helix-turn-helix domain (wHTHD) and forms a homodimer primarily via the DD, as observed for other MarR superfamily proteins. However, UrtRs are characterized by a unique N-terminal α-helix, which contributes to dimerization and UA recognition. In the absence of UA, the UrtR dimer symmetrically binds to the operator double-stranded DNA (dsDNA) by inserting its α4 recognition helix and β-stranded wing within the wHTHD into the major and minor grooves of dsDNA, respectively. Upon exposure to UA, UrtR accommodates UA in the intersubunit pocket between the DD and wHTHD. UA binding induces a conformational change in the major groove-binding core element of the UrtR wHTHD, generating a DNA binding-incompatible structure. This local allosteric mechanism of UrtR completely differs from that generally observed in other MarR superfamily members, in which the entire wHTHD undergoes effector-responsive global shifts.', 2024, 'europepmc', '{"authorString": "Song WS, Ki DU, Cho HY, Kwon OH, Cho H, Yoon SI.", "journal": null}'::jsonb),
  ('9dcde57a-275f-5348-b9f8-d8bf2f3e8a18', '41954976', '10.1093/nar/gkag293', 'A specific amount of RamA must be reached to trigger increased expression of AcrAB, enhance efflux, and confer multidrug resistance', 'Using transcriptional GFP reporters, we previously found that most antibiotics tested induced acrAB via RamA, whilst other AraC/XylS family transcriptional activators, MarA, SoxS, or Rob, induced fewer signals. Surprisingly, we found that some antibiotics induced ramA with no subsequent acrAB induction. We postulated that expression of RamA, and subsequently AcrAB, must increase above basal levels to induce acrAB transcription. Furthermore, we hypothesized that a certain level of RamA is required to induce a measurable amount of acrAB, and likewise that a certain level of AcrAB is required to give a multidrug resistant (MDR) phenotype. The transcript levels of ramA and acrAB were measured in the presence of a range of concentrations of the ramA inducer, chlorpromazine. In parallel, the levels of RamA, AcrB, and antibiotic susceptibility were determined. Here, we show that a specific level of RamA, and subsequently AcrAB, must be reached before MDR is observed, and up to a maximum amount of RamA, there was enhanced production of AcrAB and MDR; higher RamA concentrations did not increase production of AcrAB or MDR. We postulate that this was due to saturation of the maximum number of RamA binding sites in acrB.', 2026, 'europepmc', '{"authorString": "Ricci V, Piddock LJV.", "journal": null}'::jsonb),
  ('aae2eecc-b432-5281-95a9-c9b890ab3de9', '42018337', '10.1128/spectrum.02185-25', 'Identification of oxyresveratrol, a food-as-medicine substrate, as a novel EPI that targets the RND efflux pumps of &lt;i&gt;Serratia surfactantfaciens&lt;/i&gt; sp. nov. YD25&lt;sup&gt;T&lt;/sup&gt;', '<i>Serratia marcescens</i> is an opportunistic pathogen with increasing drug resistance. <i>Serratia surfactantfaciens</i> sp. nov. YD25<sup>T</sup>, a novel strain with multidrug resistance, shares similarities with <i>S. marcescens</i>. This study investigated the resistance mechanisms of YD25, with a focus on efflux pumps and their regulators. Bioinformatics analysis revealed numerous resistance genes in YD25, including five RND-type efflux pumps, SdeAB, SdeCDE, SdeGH, SdePQ-OmsA, and SdeXY. Oxyresveratrol, evernic acid, and morin were identified as efflux pump inhibitors, with oxyresveratrol showing the strongest effect targeting SdeXY and sensitizing YD25 to seven antibiotics. Among the RND pumps, SdeXY and SdeCDE are constitutively expressed and are regulated negatively by AcrR and positively by BaeSR, respectively. YD25 harbors four global regulators, including RamA, SoxS, Rob, and a novel Roblike protein. The deletion of these genes downregulated SdeXY and SdeCDE, increasing antibiotic susceptibility and confirming their role as positive regulators. Rob and Roblike exhibited functional overlap. This study elucidates the RND efflux pumps and their regulators in YD25, advancing the understanding of <i>Serratia</i> resistance mechanisms. Oxyresveratrol, a newly identified SdeXY inhibitor, offers potential for combination therapies against drug-resistant <i>Serratia</i>.<b>IMPORTANCE</b>This study reveals novel insights into <i>Serratia surfactantfaciens</i> YD25''s multidrug resistance, identifying RND efflux pumps (e.g., SdeXY and SdeCDE) as key drivers. The key discoveries include the following: (i) oxyresveratrol, a natural compound functioning as an SdeXY efflux pump inhibitor, effectively reverses bacterial resistance, thereby restoring the clinical utility of antibiotics that had been rendered nearly obsolete by drug resistance, and (ii) YD25 uniquely possesses two Rob regulators (Rob and Roblike). Despite their different origins, both positively regulate RND pump function-a finding reported for the first time in bacteria. These findings highlight the potential of natural efflux pump inhibitors against <i>Serratia</i> infections while uncovering an unusual regulatory redundancy in bacterial resistance.', 2026, 'europepmc', '{"authorString": "Liu F, Wei X, Lou Y, Wang Y, Zhang D, Cao B, Su C, Sun Y, Li Z.", "journal": null}'::jsonb),
  ('d76ab067-e766-504b-a0e8-7dfb9c0b06a6', '42293550', '10.3389/fmicb.2026.1842592', 'Plasmid-borne transcriptional regulator RamAp modulates &lt;i&gt;Salmonella&lt;/i&gt; genes for environmental and host adaptation', 'RamAp is a plasmid-borne homolog of the AraC family regulator RamA, commonly found on multidrug resistance (MDR) plasmids in <i>Salmonella</i>. Its expression is enhanced by a truncated IS<i>Ecp1</i> element, but the functional consequences of <i>ramAp</i> acquisition remain poorly characterized. In this study, we investigated whether <i>ramAp</i> modulates chromosomal gene expression in <i>Salmonella enterica</i> serovar Typhimurium LT2 and how its expression reshapes bacterial physiology and virulence-associated traits. We first assessed promoter activity using green fluorescent protein (GFP) reporter constructs. The truncated IS<i>Ecp1</i> element upstream of <i>ramAp</i> significantly increased the expression of downstream genes, supporting its role as a transcriptional enhancer. To identify the direct regulatory targets of RamAp, we focused on genes involved in membrane remodeling (<i>micF</i>), oxidative stress response (<i>sodA</i>), and motility (<i>flhDC</i>), with the efflux pump gene <i>acrAB</i> as a known positive control. Electrophoretic mobility shift assays (EMSAs) confirmed that RamAp directly binds to the upstream regulatory regions of all four genes. Functional assays revealed that <i>ramAp</i> expression increased SOD enzymatic activity, reduced swimming motility, and enhanced virulence-associated phenotypes in the <i>Galleria mellonella</i> infection model. Together, these findings demonstrate that <i>ramAp</i> reprograms host gene expression by directly engaging conserved regulatory targets, resulting in the activation of stress adaptation pathways and the repression of motility. Despite its plasmid-borne origin, RamAp functionally overlaps with chromosomal RamA while operating outside the native regulatory constraints, thereby integrating antibiotic resistance, stress resilience, and virulence-associated traits. These results highlight the adaptive potential of horizontally acquired transcriptional regulators under antibiotic pressure and host-associated stress conditions.', 2026, 'europepmc', '{"authorString": "Hong YP, Yeh WS, Wan MH, Wu YC, Chen YT, Huang WK, Yang CH, Su LY, Hong YM, Tsai PJ, Chen YT, Lin CT, Lai YC, Chiou CS, Chen YT.", "journal": null}'::jsonb),
  ('d1a4e1ec-8500-526e-a27f-5794c82ce1c8', '39745369', '10.1128/spectrum.01728-24', 'RamA upregulates the ATP-binding cassette transporter <i>mlaFEDCB</i> to mediate resistance to tetracycline-class antibiotics and the stability of membranes in <i>Klebsiella pneumoniae</i>', 'RamA is an intrinsic regulator in <i>Klebsiella pneumoniae</i>, belonging to the AraC family of transcription factors and conferring a multidrug resistance phenotype, especially for tetracycline-class antibiotics. The ATP-binding cassette transporters MlaFEDCB in bacteria play essential roles in functions essential for cell survival and intrinsic resistance to many antibiotics. We found deletion of <i>ramA</i> resulted in a fivefold decrease in the transcriptional levels of the <i>mlaFEDCB</i> operon. After complementation with ramA, the transcriptional levels were comparable to those of wild-type strain. Furthermore, an electrophoretic mobility shift assay showed that RamA could bind to the promoter region of <i>mlaEFDCB</i> operon, which confirmed RamA is an activator of <i>mlaEFDCB</i> operon. The <i>mlaEFDCB</i> operon could mildly mediate resistance to the tetracycline family of antibiotics under RamA regulation. The MIC (minimum inhibitory concentration) of tigecycline decreased fourfold, and the MIC of doxycycline, minocycline, and eravacycline decreased twofold after <i>mlaE</i>-knockout. The <i>ramA</i>- and <i>mlaE</i>-knockout strains exhibited greater sensitivity to sodium dodecyl sulfate (SDS)-EDTA than the wild-type. Growth of Δ<i>ramA</i> cells was severely compromised in 0.25/0.5% SDS and 0.55 mM EDTA, and this sensitivity was restored by complementation with <i>ramA</i> and <i>mlaE</i>. This study demonstrates that RamA can directly regulate the <i>malEFEDCB</i> operon, thereby mediating resistance to tetracycline-class antibiotics, contributing to the stability of bacterial membranes in <i>K. pneumoniae</i>. We identified a novel signal pathway in which RamA mediates multidrug resistance of <i>K. pneumoniae</i>, leading to new ideas for the development of novel antimicrobial therapeutics, therefore deserving further comprehensive study.<h4>Importance</h4>Multidrug-resistant and extensively drug-resistant <i>Klebsiella pneumoniae</i> have emerged as significant global health concerns resulting in high mortality rates. Although previous research has investigated the maintenance of lipid asymmetry (Mla) pathway, the extent to which it mediates antimicrobial resistance in <i>K. pneumoniae</i> and the underlying upstream regulatory mechanisms remain unclear. In this study, we sought to determine at the molecular level how the AraC-type global regulator RamA directly regulates mlaFEDCB, which mediates resistance to tetracycline-class antibiotics and the stability of bacterial membranes in <i>K. pneumoniae</i>.', 2025, 'europepmc', '{"authorString": "Zhao X, Zhang Y, Ju M, Yang Y, Liu H, Qin X, Xu Q, Hao M.", "journal": null}'::jsonb),
  ('87522190-57d8-50fb-aa2b-facfc6513861', '39660948', '10.1002/pro.5258', 'Targeting MarA N-terminal domain dynamics to prevent DNA binding', 'Efflux is one of the mechanisms employed by Gram-negative bacteria to become resistant to routinely used antibiotics. The inhibition of efflux by targeting their regulators is a promising strategy to re-sensitize bacterial pathogens to antibiotics. AcrAB-TolC is the main resistance-nodulation-division efflux pump in Enterobacteriaceae. MarA is an AraC/XylS family global regulator that regulates more than 40 genes related to the antimicrobial resistance phenotype, including acrAB. The aim of this work was to understand the role of the N-terminal helix of MarA in the mechanism of DNA binding. An N-terminal deletion of MarA showed that the N-terminal helix is critical for recognition of the functional marboxes. By engineering two double cysteine variants of MarA that form a disulfide bond between the N-terminal helix and the hydrophobic core of one of the helices in direct DNA contact, and combining in vitro electrophoretic mobility assays, in vivo measurements of acrAB transcription using a GFP reporter system, and molecular dynamic simulations, it was shown that the immobilization of the N-terminal helix of MarA prevents binding to DNA. This inhibited conformation seems to be universal for the monomeric members of the AraC/XylS family, as suggested by additional molecular dynamics simulations of the two-domain protein Rob. These results point to the N-terminal helix of the AraC/XylS family monomeric regulators as a promising target for the development of inhibitors.', 2025, 'europepmc', '{"authorString": "Corbella M, Moreira C, Bello-Madruga R, Torrent Burgas M, Kamerlin SCL, Blair JMA, Sancho-Vaello E.", "journal": null}'::jsonb),
  ('5b57d00c-c1ba-5281-9b36-fbef2662b652', '37815378', '10.1128/aac.00620-23', 'Antibiotics do not induce expression of <i>acrAB</i> directly but via a RamA-dependent pathway', 'The aim of this study was to determine if <i>acrAB</i> induction in <i>Salmonella</i> Typhimurium relies solely on RamA or if other transcriptional activator pathways are also involved, and to better understand the kinetics of induction of both <i>acrAB</i> and <i>ramA</i>. We evaluated the expression of <i>acrAB</i> in <i>S</i>. Typhimurium in response to a variety of compounds that are known to induce the expression of one or more of the transcriptional activators, MarA, SoxS, RamA, and Rob. We utilized green fluorescent protein (GFP) transcriptional reporter fusions to investigate the changes in the expression of <i>acrAB, ramA, marA,</i> and <i>soxS</i> following exposure to sub-inhibitory concentrations of antimicrobial compounds. Of the compounds tested, 13 induce <i>acrAB</i> expression in <i>S</i>. Typhimurium via RamA, MarA, SoxS, and Rob-dependent pathways. None of the tested antibiotics induced <i>acrAB</i> expression, and compounds that induced <i>acrAB</i> expression also induced a general stress response. The results from this study show that the majority of compounds tested induced <i>acrAB</i> via the RamA-dependent pathway. However, none of the antibiotic substrates of the AcrB efflux pump directly increased the expression of AcrAB either directly or indirectly via the induction of one of the transcriptional activators. Using a dual GFP/RFP reporter, we investigated the kinetics of the induction of <i>ramA</i> and <i>acrAB</i> simultaneously and found that <i>acrAB</i> gene expression was transient compared to <i>ramA</i> gene expression. <i>ramA</i> gene expression increased with time and would remain high or decrease slowly over the course of the experiment indicating that RamA exerts a wider global effect and is not limited to efflux regulation alone.', 2023, 'europepmc', '{"authorString": "Ricci V, Kaur J, Stone J, Piddock LJV.", "journal": null}'::jsonb),
  ('2b9d26c6-d356-5308-b8e5-7d05472c8cc2', '37220096', '10.1128/ecosalplus.esp-0010-2022', 'The Mar, Sox, and Rob Systems', 'Environments inhabited by <i>Enterobacteriaceae</i> are diverse and often stressful. This is particularly true for <i>Escherichia coli</i> and <i>Salmonella</i> during host association in the gastrointestinal systems of animals. There, <i>E. coli</i> and <i>Salmonella</i> must survive exposure to various antimicrobial compounds produced or ingested by their host. A myriad of changes to cellular physiology and metabolism are required to achieve this feat. A central regulatory network responsible for sensing and responding to intracellular chemical stressors like antibiotics are the Mar, Sox, and Rob systems found throughout the <i>Enterobacteriaceae</i>. Each of these distinct regulatory networks controls expression of an overlapping set of downstream genes whose collective effects result in increased resistance to a wide array of antimicrobial compounds. This collection of genes is known as the <i>mar-sox-rob</i> regulon. This review will provide an overview of the <i>mar-sox-rob</i> regulon and molecular architecture of the Mar, Sox, and Rob systems.', 2023, 'europepmc', '{"authorString": "Chubiz LM.", "journal": null}'::jsonb),
  ('e8093608-cc90-5837-8d5b-97291282eadc', '41278467', '10.3389/fcimb.2025.1705370', 'Characterization of &lt;i&gt;Enterobacter cloacae complex&lt;/i&gt; clinical isolates: comparative genomics and the role of the efflux pump AcrAB-TolC over-expression and NDM-1 production', '<h4>Background</h4>Carbapenem-resistant Enterobacter cloacae complex (ECC) has emerged as the third most prevalent nosocomial Enterobacterales pathogen, propelled by the synergy between intrinsic defenses, e.g. AcrAB-TolC efflux pump overexpression and horizontally acquired determinants such as the plasmid-borne <i>bla</i> <sub>NDM-1</sub>.<h4>Methods</h4>Our study employed a comprehensive, multi-faceted strategy to characterize three carbapenem-resistant, NDM-1-positive ECC isolates, named x9, F12, and x230151. The integrated methodology merged phenotypic antimicrobial susceptibility testing with functional conjugation and electroporation assays. High-resolution hybrid Nanopore-Illumina genome assemblies enabled detailed genomic annotation and extensive resistance profiling. We further quantified <i>acrAB-tolC</i> efflux pump expression via quantitative RT-PCR and reconstructed the evolutionary history of the <i>bla</i> <sub>NDM-1</sub>-<i>ble</i> <sub>MBL</sub> module using comparative plasmid genomics.<h4>Results</h4>All three ECC isolates were extensively Drug-Resistant (XDR) with carbapenem MICs ≥ 8 mg/L. Genomes carried 33-35 resistance loci, including > 5-fold up-regulated <i>acrAB-tolC</i> on chromosome, and constitutive chromosomal expression of <i>bla</i> <sub>ACT</sub>-type AmpC further blunted the activity of cephalosporins and carbapenems. The <i>bla</i> <sub>NDM-1</sub>-<i>ble</i> <sub>MBL</sub> resided on ~110-240 kb IncF/IncN/IncX3 plasmids that transferred at 3-8×10-<sup>3</sup> per donor and were embedded in Tn<i>125</i>/Tn<i>3000</i> transposons flanked by IS<i>Aba125</i>/IS<i>26</i>. These replicons also carried ESBLs (<i>bla</i> <sub>CTX-M-15</sub>), <i>bla</i> <sub>TEM-1</sub>, aminoglycoside- modifying enzymes (<i>armA</i>, <i>aadA1</i>) and intact class 1 integrons (In2, In799 and In1465). Despite>90% backbone identity of the <i>bla</i> <sub>NDM-1</sub>-<i>ble</i> <sub>MBL</sub>, the module could be reversibly excised, inverted or truncated, allowing rapid "gene-offload" and re-acquisition under shifting antibiotic pressure.<h4>Conclusion</h4>Once the carbapenem MIC surpassed 8 mg/L, the tandem action of the chromosomally over-expressed AcrAB-TolC efflux pump and plasmid-borne <i>bla</i> <sub>NDM-1</sub> carbapenemase rendered ECC virtually untreatable. Mutations in <i>ramR</i> and <i>soxR</i> regulators, as well as promoter insertions or deletions that amplify either system should also be tracked in real-time via sustained surveillance.Effective containment would require combination strategies that simultaneously inhibit efflux, neutralize β-lactamase activity, and destabilized or eliminated the IncF/IncN/IncX3 plasmids carrying <i>bla</i> <sub>NDM-1</sub>.', 2025, 'europepmc', '{"authorString": "Jiang N, Pu F, Wang W, Wang D, He J.", "journal": null}'::jsonb),
  ('a63275e2-1a5c-52e3-bb27-3affa4020075', '36308324', '10.1093/jac/dkac364', 'EnvR is a potent repressor of acrAB transcription in Salmonella', '<h4>Background</h4>Resistance nodulation division (RND) family efflux pumps, including the major pump AcrAB-TolC, are important mediators of intrinsic and evolved antibiotic resistance. Expression of these pumps is carefully controlled by a network of regulators that respond to different environmental cues. EnvR is a TetR family transcriptional regulator encoded upstream of the RND efflux pump acrEF.<h4>Methods</h4>Binding of EnvR protein upstream of acrAB was determined by electrophoretic mobility shift assays and the phenotypic consequence of envR overexpression on antimicrobial susceptibility, biofilm motility and invasion of eukaryotic cells in vitro was measured. Additionally, the global transcriptome of clinical Salmonella isolates overexpressing envR was determined by RNA-Seq.<h4>Results</h4>EnvR bound to the promoter region upstream of the genes coding for the major efflux pump AcrAB in Salmonella, inhibiting transcription and preventing production of AcrAB protein. The phenotype conferred by overexpression of envR mimicked deletion of acrB as it conferred multidrug susceptibility, decreased motility and decreased invasion into intestinal cells in vitro. Importantly, we demonstrate the clinical relevance of this regulatory mechanism because RNA-Seq revealed that a drug-susceptible clinical isolate of Salmonella had low acrB expression even though expression of its major regulator RamA was very high; this was caused by very high EnvR expression.<h4>Conclusions</h4>In summary, we show that EnvR is a potent repressor of acrAB transcription in Salmonella, and can override binding by RamA so preventing MDR to clinically useful drugs. Finding novel tools to increase EnvR expression may form the basis of a new way to prevent or treat MDR infections.', 2022, 'europepmc', '{"authorString": "Blair JMA, Siasat P, McNeil HE, Colclough A, Ricci V, Lawler AJ, Abdalaal H, Buckner MMC, Baylay A, Busby SJ, Piddock LJV.", "journal": null}'::jsonb),
  ('75e60de6-39dd-5126-be9c-49602cc871f0', '32492979', '10.3390/microorganisms8060833', 'An Intertwined Network of Regulation Controls Membrane Permeability Including Drug Influx and Efflux in Enterobacteriaceae', 'The transport of small molecules across membranes is a pivotal step for controlling the drug concentration into the bacterial cell and it efficiently contributes to the antibiotic susceptibility in <i>Enterobacteriacea</i><i>e</i>. Two types of membrane transports, passive and active, usually represented by porins and efflux pumps, are involved in this process. Importantly, the expression of these transporters and channels are modulated by an armamentarium of tangled regulatory systems. Among them, Helix-turn-Helix (HTH) family regulators (including the AraC/XylS family) and the two-component systems (TCS) play a key role in bacterial adaptation to environmental stresses and can manage a decrease of porin expression associated with an increase of efflux transporters expression. In the present review, we highlight some recent genetic and functional studies that have substantially contributed to our better understanding of the sophisticated mechanisms controlling the transport of small solutes (antibiotics) across the membrane of <i>Enterobacteriaceae</i>. This information is discussed, taking into account the worrying context of clinical antibiotic resistance and fitness of bacterial pathogens. The localization and relevance of mutations identified in the respective regulation cascades in clinical resistant strains are discussed. The possible way to bypass the membrane/transport barriers is described in the perspective of developing new therapeutic targets to combat bacterial resistance.', 2020, 'europepmc', '{"authorString": "Ferrand A, Vergalli J, Pag\u00e8s JM, Davin-Regli A.", "journal": null}'::jsonb),
  ('4686ac42-2339-5672-849e-2a3796373f7f', '34761556', '10.1002/advs.202103669', 'Structures of Class I and Class II Transcription Complexes Reveal the Molecular Basis of RamA-Dependent Transcription Activation', 'Transcription activator RamA is linked to multidrug resistance of Klebsiella pneumoniae through controlling genes that encode efflux pumps (acrA) and porin-regulating antisense RNA (micF). In bacteria, σ<sup>70</sup> , together with activators, controls the majority of genes by recruiting RNA polymerase (RNAP) to the promoter regions. RNAP and σ<sup>70</sup> form a holoenzyme that recognizes -35 and -10 promoter DNA consensus sites. Many activators bind upstream from the holoenzyme and can be broadly divided into two classes. RamA acts as a class I activator on acrA and class II activator on micF, respectively. The authors present biochemical and structural data on RamA in complex with RNAP-σ<sup>70</sup> at the two promoters and the data reveal the molecular basis for how RamA assembles and interacts with core RNAP and activates transcription that contributes to antibiotic resistance. Further, comparing with CAP/TAP complexes reveals common and activator-specific features in activator binding and uncovers distinct roles of the two C-terminal domains of RNAP α subunit.', 2022, 'europepmc', '{"authorString": "Hao M, Ye F, Jovanovic M, Kotta-Loizou I, Xu Q, Qin X, Buck M, Zhang X, Wang M.", "journal": null}'::jsonb),
  ('1749b5e4-6502-5293-8752-1cbb4301141f', '35641097', '10.1093/nar/gkac433', 'Structural basis of transcription activation by Rob, a pleiotropic AraC/XylS family regulator', 'Rob, which serves as a paradigm of the large AraC/XylS family transcription activators, regulates diverse subsets of genes involved in multidrug resistance and stress response. However, the underlying mechanism of how it engages bacterial RNA polymerase and promoter DNA to finely respond to environmental stimuli is still elusive. Here, we present two cryo-EM structures of Rob-dependent transcription activation complex (Rob-TAC) comprising of Escherichia coli RNA polymerase (RNAP), Rob-regulated promoter and Rob in alternative conformations. The structures show that a single Rob engages RNAP by interacting with RNAP αCTD and σ70R4, revealing their generally important regulatory roles. Notably, by occluding σ70R4 from binding to -35 element, Rob specifically binds to the conserved Rob binding box through its consensus HTH motifs, and retains DNA bending by aid of the accessory acidic loop. More strikingly, our ligand docking and biochemical analysis demonstrate that the large Rob C-terminal domain (Rob CTD) shares great structural similarity with the global Gyrl-like domains in effector binding and allosteric regulation, and coordinately promotes formation of competent Rob-TAC. Altogether, our structural and biochemical data highlight the detailed molecular mechanism of Rob-dependent transcription activation, and provide favorable evidences for understanding the physiological roles of the other AraC/XylS-family transcription factors.', 2022, 'europepmc', '{"authorString": "Shi J, Wang F, Li F, Wang L, Xiong Y, Wen A, Jin Y, Jin S, Gao F, Feng Z, Li J, Zhang Y, Shang Z, Wang S, Feng Y, Lin W.", "journal": null}'::jsonb),
  ('1663aef9-8f5a-5aad-8ca7-76266752e022', '31988103', '10.1128/aac.02460-19', 'Overexpression of RamA, Which Regulates Production of the Multidrug Resistance Efflux Pump AcrAB-TolC, Increases Mutation Rate and Influences Drug Resistance Phenotype', 'In <i>Enterobacteriales</i>, the AcrAB-TolC efflux pump exports substrates, including antimicrobials, from the cell. Overexpression of AcrAB-TolC can occur after exposure to fluoroquinolones, leading to multidrug resistance. The expression of AcrAB-TolC in <i>Salmonella</i> is primarily regulated by the transcriptional activator RamA. However, other transcriptional activators, such as MarA, SoxRS, and Rob, can influence AcrAB-TolC expression. This study determined whether the overproduction or absence of RamA influences the mutation rate or the phenotype of mutants selected in <i>Salmonella enterica</i> serovar Typhimurium SL1344 after ciprofloxacin exposure. The absence of RamA (SL1344 <i>ramA</i>::<i>aph</i>) resulted in mutation frequencies/rates similar to those of wild-type <i>Salmonella</i> Typhimurium SL1344. However, the overproduction of RamA (SL1344 <i>ramR</i>::<i>aph</i>) and, consequently, AcrB resulted in a significantly higher mutation frequency and rate than for wild-type <i>Salmonella</i> Typhimurium SL1344. Whole-genome sequencing revealed that in addition to selecting <i>gyrA</i> mutants resistant to quinolones, SL1344 and SL1344 <i>ramA</i>::<i>aph</i> also produced multidrug-resistant (MDR) mutants, associated with mutations in <i>soxR</i> Conversely, mutations in SL1344 <i>ramR</i>::<i>aph</i> occurred in <i>gyrA</i> only. Although transcriptional regulators such as SoxRS are believed to play a minor role in AcrAB-TolC regulation under antibiotic selective pressure, we show that <i>soxR</i> mutants can be selected after exposure to ciprofloxacin, including when RamA is absent. This demonstrates that under selective pressure, <i>Salmonella</i> can respond to increased efflux pump expression by mutating other AcrAB-TolC regulatory genes, allowing for the evolution of MDR. Understanding how <i>Salmonella</i> responds to antibiotic pressure in the absence/overproduction of RamA is important if targeting transcriptional regulators to alter efflux is to be considered an avenue for future drug discovery.', 2020, 'europepmc', '{"authorString": "Grimsey EM, Weston N, Ricci V, Stone JW, Piddock LJV.", "journal": null}'::jsonb),
  ('23626c7e-271e-5e0e-a9ec-58ce6b9ff72e', '32815626', '10.1002/jcla.23506', 'Molecular epidemiology and mechanisms of tigecycline resistance in carbapenem-resistant Klebsiella pneumoniae isolates', '<h4>Background</h4>The emergence and transmission of tigecycline- and carbapenem-resistant Klebsiella pneumoniae (TCRKP) have become a major concern to public health globally. Here, we investigated the molecular epidemiology and mechanisms of tigecycline resistance in carbapenem-resistant K pneumoniae (CRKP) isolates.<h4>Methods</h4>Forty-five non-duplicate CRKP isolates were collected from January 2017 to June 2019. We performed antimicrobial susceptibility tests, multilocus sequence typing (MLST), and pulsed-field gel electrophoresis (PFGE). PCR and DNA sequencing were performed for the detection and mutation analysis of acrR, oqxR, ramR, rpsJ, tet(A), and tet(X) genes, which are related to tigecycline resistance. The expression levels of efflux pump genes acrB and oqxB and their regulator genes rarA, ramA, soxS, and marA were assessed by quantitative real-time PCR.<h4>Results</h4>The resistance rate to tigecycline in CRKP isolates was 37.8% (17/45). K pneumoniae ST307 was a predominant clone type (70.6%, 12/17) among the TCRKP isolates. The expression levels of acrB (P < .001) and marA (P = .009) were significantly higher in the tigecycline-resistant group than in the tigecycline-intermediate and tigecycline-susceptible groups. Increased expression of acrB was associated with marA expression (r = 0.59, P = .013).<h4>Conclusions</h4>We found that the activated MarA-induced overexpression of AcrAB efflux pump plays an important role in the emergence of tigecycline resistance in CRKP isolates.', 2020, 'europepmc', '{"authorString": "Park Y, Choi Q, Kwon GC, Koo SH.", "journal": null}'::jsonb),
  ('32fbce88-ef2f-56cc-be66-3302ec5e6a11', '31501286', '10.1128/jb.00385-19', 'Multidrug Resistance Regulators MarA, SoxS, Rob, and RamA Repress Flagellar Gene Expression and Motility in Salmonella enterica Serovar Typhimurium', 'Production of flagella is costly and subject to global multilayered regulation, which is reflected in the hierarchical control of flagellar production in many bacterial species. For <i>Salmonella enterica</i> serovar Typhimurium and its relatives, global regulation of flagellar production primarily occurs through the control of <i>flhDC</i> transcription and mRNA translation. In this study, the roles of the homologous multidrug resistance regulators MarA, SoxS, Rob, and RamA (constituting the <i>mar-sox-rob</i> regulon in <i>S</i> Typhimurium) in regulating flagellar gene expression were explored. Each of these regulators was found to inhibit flagellar gene expression, production of flagella, and motility. To different degrees, repression via these transcription factors occurred through direct interactions with the <i>flhDC</i> promoter, particularly for MarA and Rob. Additionally, SoxS repressed flagellar gene expression via a posttranscriptional pathway, reducing <i>flhDC</i> translation. The roles of these transcription factors in reducing motility in the presence of salicylic acid were also elucidated, adding a genetic regulatory element to the response of <i>S</i> Typhimurium to this well-characterized chemorepellent. Integration of flagellar gene expression into the <i>mar-sox-rob</i> regulon in <i>S</i> Typhimurium contrasts with findings for closely related species such as <i>Escherichia coli</i>, providing an example of plasticity in the <i>mar-sox-rob</i> regulon throughout the <i>Enterobacteriaceae</i> family.<b>IMPORTANCE</b> The <i>mar-sox-rob</i> regulon is a large and highly conserved stress response network in the <i>Enterobacteriaceae</i> family. Although it is well characterized in <i>E. coli</i>, the extent of this regulon in related species is unclear. Here, the control of costly flagellar gene expression is connected to the <i>mar-sox-rob</i> regulon of <i>S</i> Typhimurium, contrasting with the <i>E. coli</i> regulon model. These findings demonstrate the flexibility of the <i>mar-sox-rob</i> regulon to accommodate novel regulatory targets, and they provide evidence for its broader regulatory role within this family of diverse bacteria.', 2019, 'europepmc', '{"authorString": "Thota SS, Chubiz LM.", "journal": null}'::jsonb),
  ('9e31a6ce-cfad-5c39-b9ff-58cae555fc1b', '24936054', '10.1128/jb.01838-14', 'AraC/XylS family stress response regulators Rob, SoxS, PliA, and OpiA in the fire blight pathogen Erwinia amylovora', 'Transcriptional regulators of the AraC/XylS family have been associated with multidrug resistance, organic solvent tolerance, oxidative stress, and virulence in clinically relevant enterobacteria. In the present study, we identified four homologous AraC/XylS regulators, Rob, SoxS, PliA, and OpiA, from the fire blight pathogen Erwinia amylovora Ea1189. Previous studies have shown that the regulators MarA, Rob, and SoxS from Escherichia coli mediate multiple-antibiotic resistance, primarily by upregulating the AcrAB-TolC efflux system. However, none of the four AraC/XylS regulators from E. amylovora was able to induce a multidrug resistance phenotype in the plant pathogen. Overexpression of rob led to a 2-fold increased expression of the acrA gene. However, the rob-overexpressing strain showed increased resistance to only a limited number of antibiotics. Furthermore, Rob was able to induce tolerance to organic solvents in E. amylovora by mechanisms other than efflux. We demonstrated that SoxS from E. amylovora is involved in superoxide resistance. A soxS-deficient mutant of Ea1189 was not able to grow on agar plates supplemented with the superoxide-generating agent paraquat. Furthermore, expression of soxS was induced by redox cycling agents. We identified two novel members of the AraC/XylS family in E. amylovora. PliA was highly upregulated during the early infection phase in apple rootstock and immature pear fruits. Multiple compounds were able to induce the expression of pliA, including apple leaf extracts, phenolic compounds, redox cycling agents, heavy metals, and decanoate. OpiA was shown to play a role in the regulation of osmotic and alkaline pH stress responses.', 2014, 'europepmc', '{"authorString": "Pletzer D, Schweizer G, Weingart H.", "journal": null}'::jsonb),
  ('2bb7b586-bd0a-5671-bb46-0b28039b296e', '22644028', '10.1128/aac.00456-12', 'Characterization of RarA, a novel AraC family multidrug resistance regulator in Klebsiella pneumoniae', 'Transcriptional regulators, such as SoxS, RamA, MarA, and Rob, which upregulate the AcrAB efflux pump, have been shown to be associated with multidrug resistance in clinically relevant Gram-negative bacteria. In addition to the multidrug resistance phenotype, these regulators have also been shown to play a role in the cellular metabolism and possibly the virulence potential of microbial cells. As such, the increased expression of these proteins is likely to cause pleiotropic phenotypes. Klebsiella pneumoniae is a major nosocomial pathogen which can express the SoxS, MarA, Rob, and RamA proteins, and the accompanying paper shows that the increased transcription of ramA is associated with tigecycline resistance (M. Veleba and T. Schneiders, Antimicrob. Agents Chemother. 56:4466-4467, 2012). Bioinformatic analyses of the available Klebsiella genome sequences show that an additional AraC-type regulator is encoded chromosomally. In this work, we characterize this novel AraC-type regulator, hereby called RarA (Regulator of antibiotic resistance A), which is encoded in K. pneumoniae, Enterobacter sp. 638, Serratia proteamaculans 568, and Enterobacter cloacae. We show that the overexpression of rarA results in a multidrug resistance phenotype which requires a functional AcrAB efflux pump but is independent of the other AraC regulators. Quantitative real-time PCR experiments show that rarA (MGH 78578 KPN_02968) and its neighboring efflux pump operon oqxAB (KPN_02969_02970) are consistently upregulated in clinical isolates collected from various geographical locations (Chile, Turkey, and Germany). Our results suggest that rarA overexpression upregulates the oqxAB efflux pump. Additionally, it appears that oqxR, encoding a GntR-type regulator adjacent to the oqxAB operon, is able to downregulate the expression of the oqxAB efflux pump, where OqxR complementation resulted in reductions to olaquindox MICs.', 2012, 'europepmc', '{"authorString": "Veleba M, Higgins PG, Gonzalez G, Seifert H, Schneiders T.", "journal": null}'::jsonb),
  ('e4764cb5-f52d-5196-8dee-d40aeb19f8a9', '24860636', '10.6000/1927-3037.2013.02.03.2', 'MarA, SoxS and Rob of <i>Escherichia coli</i> - Global regulators of multidrug resistance, virulence and stress response', 'Bacteria have a great capacity for adjusting their metabolism in response to environmental changes by linking extracellular stimuli to the regulation of genes by transcription factors. By working in a co-operative manner, transcription factors provide a rapid response to external threats, allowing the bacteria to survive. This review will focus on transcription factors MarA, SoxS and Rob in <i>Escherichia coli</i>, three members of the AraC family of proteins. These homologous proteins exemplify the ability to respond to multiple threats such as oxidative stress, drugs and toxic compounds, acidic pH, and host antimicrobial peptides. MarA, SoxS and Rob recognize similar DNA sequences in the promoter region of more than 40 regulatory target genes. As their regulons overlap, a finely tuned adaptive response allows <i>E. coli</i> to survive in the presence of different assaults in a co-ordinated manner. These regulators are well conserved amongst <i>Enterobacteriaceae</i> and due to their broad involvement in bacterial adaptation in the host, have recently been explored as targets to develop new anti-virulence agents. The regulators are also being examined for their roles in novel technologies such as biofuel production.', 2013, 'europepmc', '{"authorString": "Duval V, Lister IM.", "journal": null}'::jsonb),
  ('a60fbe0e-f0b2-5020-b54c-537d87129ff3', '35266867', '10.1099/mic.0.001145', 'Creatine utilization as a sole nitrogen source in <i>Pseudomonas putida</i> KT2440 is transcriptionally regulated by CahR', 'Glutamine amidotransferase-1 domain-containing AraC-family transcriptional regulators (GATRs) are present in the genomes of many bacteria, including all <i>Pseudomonas</i> species. The involvement of several characterized GATRs in amine-containing compound metabolism has been determined, but the full scope of GATR ligands and regulatory networks are still unknown. Here, we characterize <i>Pseudomonas putida</i>''s detection of the animal-derived amine compound creatine, a compound particularly enriched in muscle and ciliated cells by a creatine-specific GATR, PP_3665, here named CahR (Creatine amidohydrolase Regulator). <i>cahR</i> is necessary for transcription of the gene encoding creatinase (<i>PP_3667/creA</i>) in the presence of creatine and is critical for <i>P. putida''</i>s ability to utilize creatine as a sole source of nitrogen. The CahR/creatine regulon is small, and an electrophoretic mobility shift assay demonstrates strong and specific CahR binding only at the <i>creA</i> promoter, supporting the conclusion that much of the regulon is dependent on downstream metabolites. Phylogenetic analysis of <i>creA</i> orthologues associated with <i>cahR</i> orthologues highlights a strain distribution and organization supporting probable horizontal gene transfer, particularly evident within the genus <i>Acinetobacter</i>. This study identifies and characterizes the GATR that transcriptionally controls <i>P. putida</i>''s metabolism of creatine, broadening the scope of known GATR ligands and suggesting GATR diversification during evolution of metabolism for aliphatic nitrogen compounds.', 2022, 'europepmc', '{"authorString": "Hinkel LA, Willsey GG, Lenahan SM, Eckstrom K, Schutz KC, Wargo MJ.", "journal": null}'::jsonb),
  ('3aedaa5d-a351-5f4d-b9f0-429a376ab294', '42222030', '10.2147/idr.s596309', 'A Fitness Burden Drives the Reversion of in vitro Acquired Doxycycline Resistance in &lt;i&gt;V. cholerae&lt;/i&gt; O1', '<h4>Introduction</h4>Antibiotic exposure in both clinical and environmental settings can select for resistant isolates with expanded cross-resistance, including last-resort drugs. In <i>Vibrio cholerae</i>, such patterns emerge under sustained doxycycline exposure; however, the evolutionary dynamics and long-term stability of this adaptation remain unresolved.<h4>Methods</h4>Here, we applied long-term experimental evolution to investigate the induction, fitness-costs, and reversion of doxycycline resistance in <i>V. cholerae</i> O1. Isolates were exposed to sub-inhibitory doxycycline concentrations over 13 weeks, followed by phenotypic, genomic, and phylogenetic analyses. Resistance stability was assessed after a 2-week subculture period in the absence of doxycycline.<h4>Results</h4>Doxycycline-susceptible <i>V. cholerae</i> O1 isolates from the 2022 Lebanon outbreak evolved high-level resistance within 13 weeks of sustained exposure. The evolved resistance extended to colistin, while showing collateral sensitivity to azithromycin. Resistance imposed a marked fitness burden characterized by impaired growth and reduced yield. Notably, drug withdrawal restored both doxycycline susceptibility and fitness. Whole-genome sequencing revealed recurrent high-impact mutations in <i>tetR</i> and <i>LysR</i>-family regulators and efflux-associated pathways. Revertants were characterized by the loss of these variants and the accumulation of compensatory mutations in metabolism and membrane structure. Phylogenetic analysis showed that resistance evolved within the original lineages, with evolved isolates clustering closely with globally distributed resistant clinical strains.<h4>Conclusion</h4>Doxycycline resistance in <i>V. cholerae</i> O1 emerges rapidly under antibiotic pressure but represents a transient, high-cost adaptation that is reversible upon drug withdrawal. These findings highlight the fitness burden associated with resistance and demonstrate reproducible evolutionary trajectories, with important implications for antimicrobial stewardship strategies.', 2026, 'europepmc', '{"authorString": "Shoukair DH, Turk AZ, Kurdi A, Matar GM, Abou Fayad AG.", "journal": null}'::jsonb),
  ('42f0fcca-3b6a-59b6-b1a7-0a5b3aace5db', '41586351', '10.3389/fmicb.2025.1726803', 'Two virulent bacteriophages targeting carbapenem-resistant &lt;i&gt;Raoultella planticola&lt;/i&gt;', 'Carbapenem-resistant <i>Raoultella planticola</i> (CRRP) is an emerging nosocomial pathogen with limited therapeutic options. Here, we describe the comparative characterization of two novel virulent bacteriophages, Macy and Sally, both isolated from the same soil microenvironment. Macy exhibits exceptional lytic potency, with a burst size of 8,375 PFU per infected cell, narrow host specificity, and pronounced biofilm-disrupting activity likely mediated by a putative depolymerase. In contrast, Sally displays a broader host range, infecting both <i>R. planticola</i> and <i>R. ornithinolytica</i> (including a clinical CRRP isolate), while maintaining moderate lytic activity, notable acid tolerance, and substantial biofilm reduction. SNP analysis revealed that resistant isolates carried mutations in genes linked to surface polysaccharide biosynthesis and LysR-family transcriptional regulation, conferring resistance at a measurable cost to bacterial growth fitness. Genomic and phylogenomic analyses further revealed distinct evolutionary trajectories: Macy is a large (147.8 kb) member of Straboviridae Straboviridae with a mosaic genome related to <i>Raoultella</i> phages, whereas Sally is a compact (48.5 kb) Casjensviridae phage that is siphovirus more closely aligned with <i>Klebsiella</i> and <i>Enterobacter</i> phages. Pangenomic comparisons highlighted Macy''s strain-specific gene expansions versus Sally''s cross-genus homology, emphasizing divergent adaptation strategies. Together, these findings illustrate the complementary therapeutic potential of Macy and Sally and establish a genomic and phenotypic foundation for developing effective phage cocktails against multidrug-resistant Raoultella infections.', 2025, 'europepmc', '{"authorString": "Hoang CV, Fan J, Bhasin L, Del Mundo A, Law V, Nguyen D, Ganiger S, Mansour A, McElheny CL, Doi Y, Olawole OI.", "journal": null}'::jsonb),
  ('488df27d-d96b-59ae-b19b-9cde976fb15d', '41222146', '10.1128/mbio.02944-25', 'TetR- and LysR-type transcriptional regulators mediate multilayered control of T3SS1 by &lt;i&gt;Vibrio parahaemolyticus&lt;/i&gt; quorum sensing', 'The gram-negative pathogen <i>Vibrio parahaemolyticus</i> employs a sophisticated regulatory network to control virulence factors, including type III secretion system 1 (T3SS1), a key mediator of cytotoxicity. While the quorum sensing (QS) cascade LuxQ-ArcB-LuxO and master regulators AphA and OpaR are known to modulate T3SS1, the full scope of transcriptional regulation remains incompletely defined. Here, we combined the transcriptomic profiling of Δ<i>luxQ</i>, Δ<i>arcB</i>, and Δ<i>luxO</i> mutants with functional genetics to identify two novel transcription factors (TFs) that fine-tune T3SS1 activity. We demonstrate that TftR, a TetR family regulator, represses T3SS1 by binding the <i>opaR</i> promoter and enhancing OpaR production, thereby linking QS signaling to virulence suppression. Conversely, VltR, a LysR-type TF, directly activates <i>exsBA</i> transcription, independent of AphA/OpaR, to potentiate T3SS1-mediated cytotoxicity. Strikingly, VltR autoregulates its own expression, whereas TftR is reciprocally controlled by AphA (repressor) and OpaR (activator), revealing cross-talk between QS and accessory regulators. These findings delineate a multilayered regulatory hierarchy governing T3SS1, where TftR and VltR serve as opposing rheostats to calibrate virulence in response to cellular density and environmental cues. This work expands our understanding of <i>V. parahaemolyticus</i> pathogenicity and highlights potential targets for antivirulence therapies.IMPORTANCE<i>Vibrio parahaemolyticus</i> is a major global cause of seafood-associated gastroenteritis, relying on its tightly controlled T3SS1 for virulence. While the quorum sensing regulators AphA and OpaR are known to modulate T3SS1, the full regulatory network remains incompletely understood. This study identifies two novel transcription factors, TftR (TetR family) and VltR (LysR family), that fine-tune T3SS1 activity through distinct mechanisms. These findings reveal a multilayered regulatory hierarchy that enables <i>V. parahaemolyticus</i> to precisely calibrate virulence in response to cell density and environmental cues. Understanding these regulatory interactions provides new insights into bacterial pathogenesis and may guide the development of targeted antivirulence strategies against this clinically important pathogen.', 2025, 'europepmc', '{"authorString": "Zhang C, Wang Y, Wang C, Lu J, Yin H, Shi Y, Zhao Z.", "journal": null}'::jsonb),
  ('0a730cab-7aac-5622-b782-c2ee8757479b', '41087874', '10.1186/s12866-025-04386-6', 'Plasmid pHXY0908 confers ciprofloxacin heteroresistance to Salmonella enterica serovar typhimurium ATCC 14028 by regulating efflux pump gene expression', 'BACKGROUND: Salmonella enterica Serovar Typhimurium (S. Typhimurium) is a major global foodborne pathogen. In our previous study, the S. Typhimurium ATCC 14028 strain harboring plasmid pHXY0908 survived at fourfold its ciprofloxacin MIC (MIC0908 = 0.125 µg/mL), but the mechanism remained unclear. Heteroresistance, where minority subpopulations show elevated resistance, is among the key contributors to chronic, recurrent, and high-fatality infections. This study aimed to elucidate the molecular mechanisms by which plasmid pHXY0908 promotes ciprofloxacin heteroresistance in S. Typhimurium ATCC 14028. RESULTS: Ciprofloxacin heteroresistance in ATCC 14,028-pHXY0908 was confirmed by population analysis profiling, antimicrobial susceptibility testing, and stability assessment. Whole-genome sequencing (WGS) and transcriptome (RNA-seq) analyses were performed to identify genomic variations and global transcriptional changes linked to the development of heteroresistance. WGS revealed minimal DNA mutations in subclones with increased MIC, with no single nucleotide variants detected in known ciprofloxacin resistance genes. Notably, plasmid pHXY0908 acquisition altered chromosomal interaction domains (CIDs), potentially affecting gene regulation. Weighted gene co-expression network analysis (WGCNA) of transcriptomic profiles identified a “brown” module comprising 168 eigengenes that were significantly correlated with MIC values. Within this module, the efflux pump genes acrA, acrB, and tolC exhibited high gene significance and module membership scores. Additional candidate genes potentially contributing to ciprofloxacin heteroresistance were identified, including sodB, yhiH, yfaV, STM14_2687, and pHXY0908-99. Notably, STM14_2687 (a LysR-type transcriptional regulator), negatively regulated acrAB-tolC; its overexpression suppressed acrA and enhancing susceptibility to ciprofloxacin. Furthermore, functional validation demonstrated that plasmid pHXY0908 could confer heteroresistance to ciprofloxacin in other Salmonella enterica strains, Escherichia coli, and Klebsiella pneumoniae, suggesting its broad-host-range potential in mediating heteroresistance. CONCLUSION: Our study reveals that transcriptional regulation drives ciprofloxacin heteroresistance in S. Typhimurium ATCC 14028 carrying plasmid pHXY0908. We show that regulation of efflux pumps (e.g., acrAB-tolC), superoxide dismutase (sodB), DNA protection systems, and regulatory networks contributes to heteroresistance development. Plasmid pHXY0908 acquisition was found to confer ciprofloxacin heteroresistance across species, suggesting its potential for horizontal transfer and increased transmission risk. Notably, STM14_2687 was identified and validated as a transcription factor that represses acrAB-tolC expression and may serve as a potential therapeutic target.', 2025, 'europepmc', '{"authorString": "Li M, Feng X, Jian Q, Jing M, Wang X, Cui Z, Zhang R, Sun J, Liu Y, Liao X, Lian X.", "journal": null}'::jsonb),
  ('7896a461-644d-54c5-a8cc-41778ec34a9c', '41906866', '10.1021/acs.jafc.5c12363', 'The Crucial Role of LTTR_0390 in &lt;i&gt;Burkholderia gladioli&lt;/i&gt; BBB-01 in Orchestrating Antibiotic Production, Quorum-Sensing Responses, and Pathogenicity on Mushrooms', '<i>Burkholderia gladioli</i> strain BBB-01, classified as <i>B. gladioli</i> pv <i>agaricicola</i>, displays broad antagonism against diverse pathogens. We investigated the regulatory role of the LysR-type transcriptional regulator LTTR_0390 and its potential involvement in pathogenicity toward the cultivated button mushroom (<i>Agaricus bisporus</i>). Using insertional mutagenesis, metabolite profiling, transcriptomic analysis, and phenotypic assays, we found that disruption of the <i>lttr_0390</i> gene extensively reprograms secondary metabolism, for example, upregulating the gladiostatin biosynthetic gene cluster while downregulating the gladiolin cluster. Although this gene disruption did not affect production of quorum-sensing (QS) autoinducers, the mutant exhibited reduced QS-linked behaviors, including motility and biofilm formation. Additionally, disruption of <i>lttr_0390</i> markedly diminished soft rot symptoms on <i>A. bisporus</i> fruiting bodies. Together, these findings identify LTTR_0390 as a global regulator that coordinates secondary metabolism and QS-linked behaviors while decoupling antifungal activity from mushroom damage.', 2026, 'europepmc', '{"authorString": "Diyapoglu A, Liu YY, Abay A, Lin KH, Lo IW, Chang CF, Huang YP, Chung CT, Li TL, Meng M.", "journal": null}'::jsonb),
  ('edac53c0-8d54-5066-8ecf-962126c71b05', '41563046', '10.1128/aac.01041-25', 'Phenotypic and genomic characterization of &lt;i&gt;Roseomonas mucosa&lt;/i&gt;, an opportunistic pathogen with discrepancies among antimicrobial susceptibility testing methods', '<i>Roseomonas mucosa</i> is an opportunistic bacterium found in clinical and environmental samples that primarily affects immunocompromised patients. Treatment is challenging owing to the lack of standardized susceptibility testing methods, breakpoints, and variable antimicrobial resistance profiles published. This study evaluated different antimicrobial susceptibility testing approaches and searched for new insights into resistance mechanisms, especially against third-generation cephalosporins. Antimicrobial susceptibility profiles of a panel of 17 <i>R</i>. <i>mucosa</i> strains were analyzed using disk diffusion method (DDM), broth microdilution (BMD) method, and MIC gradient strips. Discrepancies between susceptibility methods were further explored using beta-lactamase inhibitors, whole-genome sequencing, and transcriptomic analyses. Antimicrobial susceptibility testing revealed high susceptibility to aminoglycosides, fluoroquinolones, and carbapenems, while resistance to many beta-lactams was detected. Significant discrepancies were observed between the DDM and BMD methods, particularly with respect to the use of third- and fourth-generation cephalosporins and aztreonam. Genomic analysis identified two putative class-A and one class-C beta-lactamases within all strains. Transcription of one class A beta-lactamase, controlled by an <i>lysR</i> regulator, was significantly induced by cephalosporins and explained the phenotype observed. This study provides the antimicrobial susceptibility profiles against a large panel of antibiotics from 17 <i>R</i>. <i>mucosa</i> strains. It also explained the deep discrepancies between phenotypic approaches regarding cephalosporins.', 2026, 'europepmc', '{"authorString": "Cotet C, Galopin S, Creach A-E, Tenouri M, Le Pont C, Laquay N, Giard J-C, Le Hello S, Gravey F.", "journal": null}'::jsonb),
  ('72200474-12f4-57be-b743-87cf755599cf', '41797538', '10.1093/nar/gkag204', 'LysR-type regulator LrhA promotes CRISPR-Cas immunity in Escherichia coli', 'The CRISPR-Cas defense system safeguards prokaryotes against foreign genetic elements. Its activity is determined by the combined effects of adaptation and interference. However, the dynamic regulation of these two processes remains not fully understood. In this study, we identify the LysR-type transcriptional regulator LrhA, which is differentially expressed in various Escherichia coli strains, as a novel CRISPR-Cas activator that plays a critical role in modulating host defense levels. In a representative strain expressing a high level of LrhA, the regulator enhances CRISPR-Cas-mediated adaptive immunity against bacteriophage infection by promoting cas gene transcription through direct interaction with the promoter of the cas operon. Moderate activation of cas genes by weakly expressed LrhA in another representative strain efficiently accelerates the clearance of horizontally transferred CRISPR-targeted plasmids by enhancing spacer acquisition via interference-driven adaptation. This divergence, likely a result of genome evolution, suggests that adaptive immunity is optimized with intermediate transcription levels of cas genes by triggering positive feedback between adaptation and interference. Collectively, our findings highlight the crucial role of LrhA in fine-tuning host defense responses.', 2026, 'europepmc', '{"authorString": "Fang M, Yap J, Fei M, Gong M, Li N, Lu Y, Yu M, Xu Y, Wu F, Gao H, Sun D.", "journal": null}'::jsonb),
  ('b4ea19ee-1e7b-596d-af47-5a402f084b9e', '39306765', '10.1021/acssynbio.4c00219', 'Fundamentals and Exceptions of the LysR-type Transcriptional Regulators', 'LysR-type transcriptional regulators (LTTRs) are emerging as a promising group of macromolecules for the field of biosensors. As the largest family of bacterial transcription factors, the LTTRs represent a vast and mostly untapped repertoire of sensor proteins. To fully harness these regulators for transcription factor-based biosensor development, it is crucial to understand their underlying mechanisms and functionalities. In the first part, this Review discusses the established model and features of LTTRs. As dual-function regulators, these inducible transcription factors exude precise control over their regulatory targets. In the second part of this Review, an overview is given of the exceptions to the "classic" LTTR model. While a general regulatory mechanism has helped elucidate the intricate regulation performed by LTTRs, it is essential to recognize the variations within the family. By combining this knowledge, characterization of new regulators can be done more efficiently and accurately, accelerating the expansion of transcriptional sensors for biosensor development. Unlocking the pool of LTTRs would significantly expand the currently limited range of detectable molecules and regulatory functions available for the implementation of novel synthetic genetic circuitry.', 2024, 'europepmc', '{"authorString": "Demeester W, De Paepe B, De Mey M.", "journal": null}'::jsonb),
  ('4489f8db-93f0-5405-80e4-b5e43e60bcd3', '40767521', '10.1128/mbio.01498-25', 'Dual regulatory role of cyclic di-GMP via the DgcY/HhmR complex in salt response of &lt;i&gt;Halomonas hydrothermalis&lt;/i&gt; Y2', 'Bis-(3''-5'')-cyclic dimeric guanosine monophosphate (c-di-GMP) is a key second messenger synthesized by diguanylate cyclases (DGCs) and regulates diverse bacterial behaviors. While many DGC modules are integrated within complex regulatory cassettes to ensure precise control of cellular processes, simpler DGC-containing cassettes are also widespread across bacteria, despite the regulative modes of their DGC activity remaining to be explored. In this study, we characterized a unique regulative network within a simple DGC cassette in <i>Halomonas hydrothermalis</i> Y2, DgcY, which comprises a six-transmembrane domain and a GGDEF domain lacking the canonical autoinhibitory site. In-frame deletion of <i>dgcY</i> significantly impaired the biofilm formation and strain growth under high-salt stress, particularly at lower temperatures. Notably, we uncovered a novel feedback inhibition mechanism in this strain, whereby c-di-GMP suppresses DgcY activity by facilitating the formation of a complex between DgcY and a LysR-type transcriptional regulator, HhmR. This interaction, mediated by the regulatory domain of HhmR, obviously reduced DgcY activity, especially in the presence of c-di-GMP. Functionally, the deletion of <i>hhmR</i> remarkably affected the swimming motility and biofilm formation of <i>H. hydrothermalis</i> Y2. Collectively, these findings revealed a collaborative feedback regulatory mode, in which c-di-GMP cooperates with a transcriptional regulator to modulate the DGC activity, thereby regulating signal transduction and bacterial adaptation to osmotic stress.<h4>Importance</h4>Generally, c-di-GMP exerts negative feedback on DGC activity by binding to the autoinhibitory site of DGCs or functioning as a downstream effector for transcriptional regulators. In this study, we revealed a previously unrecognized mode of feedback inhibition, in which c-di-GMP indirectly suppresses DgcY activity by promoting complex formation between DgcY and a LysR-type transcriptional regulator. Moreover, this DGC-associated network contributed to bacterial adaptation under osmotic stress at low temperatures, providing new insight into how c-di-GMP signaling pathways are integrated in the cellular osmotic regulation.', 2025, 'europepmc', '{"authorString": "Zhang Y, Wang W, Liu Y, Li C, Liu J, Feng L, Gao Y, Peng Y, Wang W, Li C, Xu P, Yang C.", "journal": null}'::jsonb),
  ('7711d36b-6083-5473-ad98-e86bcc0d665b', '37796010', '10.1128/aem.01184-23', 'Membrane-enclosed <i>Pseudomonas</i> quinolone signal attenuates bacterial virulence by interfering with quorum sensing', 'Outer membrane vesicle (OMV)-delivered <i>Pseudomonas</i> quinolone signal (PQS) plays a critical role in cell-cell communication in <i>Pseudomonas aeruginosa</i>. However, the functions and mechanisms of membrane-enclosed PQS in interspecies communication in microbial communities are not clear. Here, we demonstrate that PQS delivered by both OMVs from <i>P. aeruginosa</i> and liposome reduces the competitiveness of <i>Burkholderia cenocepacia</i>, which usually shares the same niche in the lungs of cystic fibrosis patients, by interfering with quorum sensing (QS) in <i>B. cenocepacia</i> through the LysR-type regulator ShvR. Intriguingly, we found that ShvR regulates the production of the QS signals cis-2-dodecenoic acid (BDSF) and N-acyl homoserine lactone (AHL) by directly binding to the promoters of signal synthase-encoding genes. Perception of PQS influences the regulatory activity of ShvR and thus ultimately reduces QS signal production and virulence in <i>B. cenocepacia</i>. Our findings provide insights into the interspecies communication mediated by the membrane-enclosed QS signal among bacterial species residing in the same microbial community.IMPORTANCEQuorum sensing (QS) is a ubiquitous cell-to-cell communication mechanism. Previous studies showed that <i>Burkholderia cenocepacia</i> mainly employs cis-2-dodecenoic acid (BDSF) and N-acyl homoserine lactone (AHL) QS systems to regulate biological functions and virulence. Here, we demonstrate that <i>Pseudomonas</i> quinolone signal (PQS) delivered by outer membrane vesicles from <i>Pseudomonas aeruginosa</i> or liposome attenuates <i>B. cenocepacia</i> virulence by targeting the LysR-type regulator ShvR, which regulates the production of the QS signals BDSF and AHL in <i>B. cenocepaci</i>a. Our results not only suggest the important roles of membrane-enclosed PQS in interspecies and interkingdom communications but also provide a new perspective on the use of functional nanocarriers loaded with QS inhibitors for treating pathogen infections.', 2023, 'europepmc', '{"authorString": "Li X, Wang G, Guo Q, Cui B, Wang M, Song S, Yang L, Deng Y.", "journal": null}'::jsonb),
  ('a703481f-a8a0-585f-90d5-fc08c487e997', '42112446', '10.3389/fmicb.2026.1802731', 'Exploring allosteric efflux pump inhibitors and the role of bacterial membrane potential in modulating drug resistance', 'Multi-drug resistance (MDR) bacteria pose a significant global health challenge, primarily driven by the activity of multi-drug efflux pumps and their intimate coupling to bacterial membrane bioenergetics. Among these systems, proton-motive force (PMF) dependent Resistance, Nodulation-Division (RND) efflux pumps, such as AcrAB-TolC, play a central role in both intrinsic and acquired antibiotic resistance by expelling structurally diverse antimicrobial agents. Recent evidence indicates that efflux pumps are not merely drug extrusion devices but also key regulators of bacterial physiology, influencing membrane potential, redox balance, metabolic state, stress adaptation, and growth-phase transitions. Structural and mechanistic advances have uncovered conserved allosteric sites within RND pumps that are distinct from substrate-binding pockets, enabling the development of allosteric efflux pump inhibitors (EPIs) that disrupt conformational cycling and proton relay without competing with antibiotics. Pyridylpiperazine-based inhibitors, including BDM-series compounds, have demonstrated potent efflux inhibition, antibiotic potentiation, and <i>in-vivo</i> efficacy in preclinical models. This review integrates current knowledge on efflux pump architecture, PMF-driven transport mechanisms, membrane potential dynamics, and allosteric inhibition, emphasizing the therapeutic potential of dual-targeting strategies that combine efflux inhibition with bioenergetics disruption. This study also focused on translational challenges, including drug penetration, resistance evolution, and pharmacokinetic constraints, and future directions for incorporating efflux-bioenergetic targeting into next-generation antimicrobial discovery pipelines to restore antibiotic efficacy against MDR Gram-negative pathogens.', 2026, 'europepmc', '{"authorString": "Hada APS, Meena KR, Jitendra, Singh G, Arya H, Kumar A.", "journal": null}'::jsonb),
  ('78124899-6313-534d-91b9-aa2b94cd7468', '42404788', '10.3389/fmicb.2026.1859451', 'A review of research progress on periplasmic adaptor proteins in bacterial tripartite pumps', 'Gram-negative bacteria exhibit higher intrinsic resistance to antimicrobial agents than Gram-positive bacteria, largely attributable to their efficient multidrug efflux pumps. Among these, tripartite pumps spanning the inner membrane, periplasm, and outer membrane are central to both intrinsic and acquired resistance. Periplasmic adaptor proteins (PAPs) serve as the core connectors of these systems. Once regarded merely as passive scaffolds, PAPs are now confirmed to function as dynamic allosteric couplers that mediate complex assembly and conformational coordination. Moving beyond structural descriptions, this review synthesizes recent advances regarding the structural architecture of PAPs across RND (Resistance-Nodulation-Division), MFS (Major Facilitator Superfamily), and ABC (ATP-Binding Cassette) superfamilies, highlighting their conserved domains and subtype-specific adaptations. We place special emphasis on the multifaceted roles of PAPs-from substrate recognition and environmental sensing to their surprising function as extracellular "public goods" in bacterial necrosignaling. Furthermore, we dissect the clinical epidemiology of PAP overexpression and evaluate the potential of targeting PAPs with novel inhibitors. By reframing PAPs as active regulatory hubs rather than static linkers, this review elucidates the assembly logic of tripartite efflux mechanisms and provides a theoretical basis for combating antimicrobial resistance.', 2026, 'europepmc', '{"authorString": "Feng Z, Huang X, Chen Y, Qiu C, Liu D.", "journal": null}'::jsonb),
  ('292e9a50-bf6e-540f-95cb-be77dbefe4aa', '42278334', '10.3390/ijms27114804', 'Medicinal Plants: A Promising Therapeutic Approach for Addressing Antimicrobial Resistance', 'Antimicrobial resistance (AMR) is a critical global public health crisis that is being exacerbated by widespread misuse of antibiotics and rapid bacterial adaptation. The progressive decrease in antibiotic efficacy is also compounded by a stagnating drug-discovery pipeline and underscores the urgent need for innovative and sustainable antimicrobial strategies. This review systematically delineates the core molecular mechanisms driving bacterial resistance, including enzymatic drug inactivation, target modification, reduced membrane permeability, and multidrug efflux pump overexpression. Furthermore, the potential of (flavonoids, alkaloids, and phenolics) as structurally diverse plant-derived compounds with multi-target activity is comprehensively assessed. The features of multi-target activity make them promising dual-function agents that may be capable of both direct antimicrobial action and resistance modulation. These natural products have distinct mechanisms from conventional antibiotics, low propensity for resistance, and versatile bioactivity as biofilm disruptors, enzyme inhibitors, and efflux pump blockers. Numerous phytochemicals exhibit potent synergistic effects with available antibiotics by effectively resensitizing resistant pathogens and extending the clinical utility of current antimicrobials. By integrating mechanistic understanding with translational potential, this review discusses phytochemicals as a sustainable resource for developing next-generation antimicrobial strategies as a complementary approach to revitalize therapeutic pipelines and combat multidrug-resistant infections.', 2026, 'europepmc', '{"authorString": "Zhou H, Du J, Jia M, Li Y, Zheng K.", "journal": null}'::jsonb),
  ('12ada8d0-14e4-5f1e-93d4-732c2f29808d', '42182029', '10.3389/fmicb.2026.1811959', 'Genes and physiological strategies in bacterial antibiotic resistance', 'Bacteria display an incredible genetic plasticity, which enables them to adapt to various environmental stressors, such as antibiotic compounds that may imperil their existence. Bacterial resistance mechanisms include degradative enzymes, inactivation of antibiotics, antibacterial target site mutation, change in target, altered cell wall permeability to antibiotics, bypass of metabolic pathways, and efflux pumping of antibiotics across the cell membrane. These mechanisms are encoded by genomic changes ranging from point mutation via genetic elements assembly to horizontal transfer of genes from the environment. Antibiotic resistance in bacteria can be inherited or acquired. Antibacterial resistance genes may accumulate mobile elements, leading to multi-drug-resistant phenotypic transfer via a single genetic event. The resistance to antibiotics has been frequently increasing in clinical settings, which drives scientists to research alternative antibacterial medicines to prevent the growth and spread of drug-resistant bacteria. Technological advancements and the discovery of innovative drug moieties with targeting potential have led to the development of novel drug compounds with diverse therapeutic properties. This includes alternative cellular, physiological, and metabolic patterns of bacteria that may be potential pharmacological targets for the next generation of antibiotics. It is beneficial to characterize antibiotic resistance genotypes and phenotypes causing antibiotic bacterial resistance. An understanding of mechanisms that lead to the development and spread of antibiotic resistance will help clinicians in making appropriate decisions regarding antibiotic usage in a wide range of circumstances. The current review has highlighted the mechanism of drug resistance in bacteria, and has enlisted the antibiotic resistance genes (ARGs) and their importance in aggravating the resistance phenomenon.', 2026, 'europepmc', '{"authorString": "Nadeem MS, Rasool R, Afzal M, Ullah I, Murtaza BN, Daoub RMA, Chaieb K, Alzarea SI, Kazmi I, Ashraf GM.", "journal": null}'::jsonb),
  ('2cfcba8b-51a2-5b15-845e-587cf9b41da8', '42002144', '10.1016/j.jgar.2026.04.005', 'Emergence of mobile RND-type efflux pump gene cluster tmexCD-toprJ on a broad-host-range IncC plasmid in Shewanella species in a water environment', '<h4>Objectives</h4>The spread of the mobile resistance-nodulation-division (RND)-type efflux pump tmexCD-toprJ gene cluster that confers multidrug resistance (MDR), including tigecycline resistance, in gram-negative bacteria poses a global public health threat. However, the occurrence of such clinically important antimicrobial resistance genes (ARGs) in the natural environments has not yet been well investigated. In this study, we investigated MDR aquatic bacteria in Vietnam.<h4>Methods</h4>A carbapenem- and tigecycline-resistant Shewanella xiamenensis isolate NUITM-VS2 was obtained from urban drainage in Hanoi, Vietnam, in October 2021. Antimicrobial susceptibility testing using agar dilution and whole-genome sequencing (WGS) was performed using both long-read and short-read sequencers. ARGs and plasmid replicons were detected using ResFinder and PlasmidFinder with the custom sequence database.<h4>Results</h4>NUITM-VS2 showed resistance to most antimicrobials tested, including tigecycline, tetracyclines, carbapenems, cephalosporins, fluoroquinolone, and aminoglycosides. WGS analysis resulted in the complete genome sequence consisting of one chromosome and five plasmids. A 152.2-kb IncC plasmid, pNUITM-VS2_2, co-carried two mobile tigecycline resistance genes, tet(X4) and tmexCD3-toprJ1b-like gene cluster. In addition, a 24.8-kb untypeable plasmid, pNUITM-VS2_4, carried the carbapenemase gene bla<sub>NDM-1</sub>. pNUITM-VS2_2 was transferred to Escherichia coli by conjugation, which simultaneously conferred high-level resistance against many antimicrobials, including tigecycline.<h4>Conclusion</h4>To the best of our knowledge, this is the first report of the detection of the mobile RND-type efflux pump gene cluster tmexCD-toprJ in Shewanella species. Our results provide genetic evidence of the complexity of the dynamics of clinically important ARGs among aquatic bacteria, which could be important reservoirs for ARGs in the natural environment.', 2026, 'europepmc', '{"authorString": "Dao DT, Takemura T, Kasuga I, Hirabayashi A, Nga NT, Anh PHQ, Tu ND, Trang LT, Thai PD, Tran HH, Abe H, Hasebe F, Shibayama K, Suzuki M.", "journal": null}'::jsonb),
  ('7e028964-b155-573e-b803-b3384090fc7b', '42046692', '10.14202/vetworld.2026.948-963', 'Multidrug-resistant &lt;i&gt;Escherichia coli&lt;/i&gt; causing diarrhea in yak calves on the Qinghai-Tibet Plateau: phenotypic characterization, whole-genome sequencing, and pathogenicity analysis', '<h4>Background and aim</h4>Calf diarrhea represents a major threat to yak (<i>Bos grunniens</i>) husbandry on the Qinghai-Tibet Plateau, where extreme environmental conditions (high altitude, low oxygen, cold temperatures) and irregular antibiotic use may accelerate the emergence of multidrug-resistant (MDR) bacterial pathogens. This study aimed to isolate and identify the predominant bacterial agents responsible for diarrhea in yak calves, determine their antimicrobial resistance profiles, and investigate the genomic features and pathogenicity of the most resistant strain to provide evidence-based guidance for prevention and control.<h4>Materials and methods</h4>Rectal swabs were collected from 12 naturally diarrheic yak calves across four geographically distinct farms in Huangyuan County, Qinghai Province, during the peak season (June-July). Bacterial isolates were obtained through enrichment in Luria-Bertani broth followed by plating on Luria-Bertani agar, and identified by Gram staining, <i>16S rRNA</i> gene amplification (primers 27F/1492R), and Sanger sequencing with BLAST comparison (>99.5% identity). Antimicrobial susceptibility was assessed using the Kirby-Bauer disk diffusion method with 17 antibiotics representing eight classes, interpreted according to Clinical and Laboratory Standards Institute VET08-Ed4 breakpoints. The most MDR isolate (HYCQ01) underwent whole-genome sequencing (WGS) on the Oxford Nanopore Technologies MinION platform. Genome assembly quality was evaluated with BUSCO v5.4.7; virulence factors and antibiotic resistance genes were annotated against the Virulence Factor Database and Comprehensive Antibiotic Resistance Database, respectively (BLASTP, e-value ≤ 1e-5, identity ≥ 40%, length ≥ 50 bp). Pathogenicity was tested in 20 male C57BL/6 mice (7-8 weeks, 20 ± 2 g) via intraperitoneal injection of 1.0 × 10<sup>8</sup> colony-forming units/mL bacterial suspension (100 μl/kg); survival was monitored, and organ histopathology (heart, jejunum, kidneys, liver, lungs, spleen) was examined after hematoxylin-eosin staining. All animal procedures were approved by the Experimental Animal Ethics Committee (No. 2024-030). Data were analyzed using GraphPad Prism 10.1.2 with one-way analysis of variance.<h4>Results</h4>Eight <i>Escherichia coli</i> strains were isolated from the 12 samples and confirmed by <i>16S rRNA</i> sequencing. All isolates displayed MDR phenotypes, showing 100% resistance to penicillin G and clindamycin, 87.5% to sulfafurazole, and 75.0% to erythromycin. WGS of HYCQ01 revealed 32 resistance classes and 152 resistance genes, consistent with its phenotype (including β-lactamases, macrolide-lincosamide resistance determinants, and tetracycline efflux pumps). Virulence genes included Type III secretion system components, alginate biofilm regulators, iron acquisition systems (<i>pvdE</i>), and hemolysins (<i>rck</i>). Phylogenetically, HYCQ01 clustered near enterotoxigenic <i>E. coli</i> O139:H28 but exhibited a hybrid profile combining animal-associated colonization factors (F17, CFA/I) with atypical extraintestinal traits. In the mouse model, HYCQ01 induced 100% mortality within 27 h post-challenge (p < 0.0001) and caused severe histopathological damage in spleen and jejunum, indicating strong systemic invasiveness.<h4>Conclusion</h4>MDR <i>E. coli</i>, exemplified by the hybrid strain HYCQ01, predominates as a causative agent of yak calf diarrhea on the Qinghai-Tibet Plateau, shaped by local ecological pressures and horizontal gene transfer. These results highlight the urgent need for region-specific antimicrobial resistance surveillance, rational antibiotic stewardship, and exploration of non-antibiotic alternatives (probiotics, plant-derived antimicrobials) within a One Health framework. WGS data are deposited at NCBI under BioProject PRJNA1289237.', 2026, 'europepmc', '{"authorString": "Chen Q, Wu D, Yang Z, Sun C, Tang S, Chen C, Wei B, Liu Q, Bai P, Zhang H, Wang S, Hao B.", "journal": null}'::jsonb),
  ('9335f1f9-55ec-5bec-9d87-9a419152f817', '42017668', '10.1128/aem.02575-25', 'Efflux pump activation confers mupirocin resistance and enhances rhizosphere fitness in &lt;i&gt;Pseudomonas&lt;/i&gt;', 'Mupirocin (Mup) is a polyketide antibiotic for clinical methicillin-resistant <i>Staphylococcus aureus</i> treatment and agricultural biocontrol, acting by binding to IleRS to inhibit protein synthesis. Here, we demonstrate that <i>Pseudomonas viciae</i> 11K1 acquires resistance to mupirocin not through canonical mutations in <i>ileS</i>, the gene encoding the drug target, but via single-nucleotide polymorphisms (SNPs) of EmhR, a transcriptional repressor. These SNPs attenuate EmhR''s DNA-binding ability, resulting in derepression of the resistance-nodulation-division (RND) efflux pump EmhABC. This leads to a 7-fold (to 800 μg/mL) increase in the mupirocin minimum inhibitory concentration and confers cross-resistance to multiple other antibiotics. Critically, 11K1 strains harboring EmhR mutations exhibit enhanced competitive fitness in colonizing wheat rhizospheres against the mupirocin-producing <i>Pseudomonas bijieensis</i> 2P24. The conservation of this regulatory mechanism in <i>Pseudomonas aeruginosa</i>, mediated by the EmhR ortholog NalD, underscores its broader biological significance. Our findings establish a direct link between efflux pump regulation and ecological adaptation, highlighting a key mechanism that contributes to environmental antimicrobial resistance and has important implications for the clinical and agricultural use of mupirocin.IMPORTANCEMupirocin and its producing <i>Pseudomonas</i> strains are widely used in both clinical and agricultural contexts, making mupirocin resistance a significant concern for public health and food security. While canonical mupirocin resistance is primarily attributed to mutations in <i>ileS</i>, the gene encoding the drug target isoleucyl-tRNA synthetase (IleRS), our study identifies a novel resistance mechanism in <i>Pseudomonas viciae</i> strain 11K1 mediated by single-nucleotide polymorphisms (SNPs) in the transcriptional repressor EmhR. These SNPs derepress the RND efflux system EmhABC and reduce intracellular mupirocin levels. This mechanism not only enhances resistance to mupirocin but also confers cross-resistance to multiple antimicrobial agents, raising the risk of multidrug-resistant strain spread. EmhR-mutant 11K1 strains exhibit enhanced rhizosphere competitiveness in the presence of mupirocin-producing <i>Pseudomonas bijieensis</i> strain 2P24, indicating an ecological fitness advantage that could promote resistant population expansion in agricultural environments. The same regulatory pathway is conserved in human pathogen <i>Pseudomonas aeruginosa</i> PAO1 via the functional ortholog NalD, suggesting that this mechanism may be widespread in <i>Pseudomonas</i>. These findings fill a critical gap in understanding non-target-based mupirocin resistance, clarify the ecological drivers of antimicrobial resistance, and offer practical insight for improving mupirocin application to limit the emergence and spread of resistant pathogens.', 2026, 'europepmc', '{"authorString": "Wang W-J, Wang M-J, Jiang W-J, Zhang L-Q.", "journal": null}'::jsonb),
  ('96ef9aa0-d20d-5ff1-be84-a6e28e9c9dc5', '42133740', '10.1371/journal.ppat.1014228', 'How resistance-nodulation-division (RND) efflux pumps contribute to virulence', 'In Gram-negative bacteria, multi-subunit efflux pumps transport molecules across the inner membrane, periplasm, and outer membrane to the extracellular environment. These efflux pumps include the Resistance-Nodulation-Cell Division (RND) superfamily, which utilize the membrane proton motive force to export a wide range of substrates against a concentration gradient. RND efflux pumps have been extensively studied for their fundamental role in the export of antibiotics, but they also play multifaceted roles in bacterial physiology. Notably, they are required for pathogen survival in the mammalian host when antibiotics are absent, an emerging aspect of their biology that is not well understood. Here, we analyze the evidence supporting several intertwined mechanistic hypotheses regarding the requirement for RND efflux pumps during infection. To do this, we explore why host- and bacterial-derived substrates need to be exported during pathogenesis, and the effects of proton translocation from the periplasm to the cytosol. We close by highlighting knowledge gaps and directions for future work regarding the role of RND efflux pumps in bacterial virulence.', 2026, 'europepmc', '{"authorString": "Detweiler CS, Alav I.", "journal": null}'::jsonb),
  ('905a659c-5e67-5b08-9ba2-e0078ab23781', '41814172', '10.1186/s12866-026-04847-6', 'Genetic variants of AcrAB and OqxAB and the impact of efflux pump inhibition on ciprofloxacin and amikacin resistance in clinical isolates of Klebsiella pneumoniae from Lima, Peru', 'BACKGROUND: Klebsiella pneumoniae is a World Health Organization priority pathogen because of its rapidly accumulating resistance to multiple drug classes. Over-expression of the AcrAB and OqxAB Resistance-Nodulation-Division (RND) efflux pumps is a key mechanism, yet genomic data on these systems in Peruvian strains are scarce. METHODS: Sixteen non-duplicate K. pneumoniae isolates obtained from hospitalised patients in Lima (2019–2020) were tested for ciprofloxacin and amikacin susceptibility by broth microdilution, with and without the efflux-pump inhibitors carbonyl cyanide m-chlorophenylhydrazone (CCCP) and phenylalanine-arginine β-naphthylamide (PAβN). AcrA, AcrB, OqxA and OqxB were detected by PCR, and the resulting amplicons were sequenced on the Oxford Nanopore platform. Reads were analysed with Epi2me (Amplicon workflow); single nucleotide polymorphisms (SNPs) were identified by aligning to reference sequences in MEGA, and all sequences were deposited in GenBank. RESULTS: Resistance to ciprofloxacin and amikacin was evaluated in all isolates; 93.8% were resistant to ciprofloxacin and 18.8% to amikacin. PAβN produced a ≥ 4-fold MIC reduction in 18.8% (ciprofloxacin) and 100% (amikacin) of resistant strains; CCCP yielded a ≥ 3-fold decrease in 75% of ciprofloxacin resistant isolates. AcrB and AcrA were detected in 56.3% and 43.8% of isolates, while OqxB and OqxA occurred in 25.0% and 31.3%, respectively. Nanopore sequencing con-firmed gene identity and revealed 12 SNPs detected, OqxB c.56 G > T (V19F) and c.356 C > A (P119H), which may modulate efflux efficiency. CONCLUSION: Efflux-mediated resistance to ciprofloxacin and amikacin in clinical isolates of K. pneumoniae is underpinned by genetic variants in the AcrAB and OqxAB pumps. The incorporation of long-read amplicon sequencing exposes SNP-level variation missed by conventional PCR studies and underscores the value of routine genomic surveillance. The MIC reversals observed with PAβN and CCCP against these two antibiotics highlight efflux pump inhibition as a promising complementary strategy against resistant K. pneumoniae.', 2026, 'europepmc', '{"authorString": "Aguilar-Luis D, Silva-Caso W, P\u00e9rez-Lazo G, Morales-Castillo L, Camps M, Soto-Febres F, Aguilar-Luis MA, Aquino-Ortega R, Del Valle-Mendoza J.", "journal": null}'::jsonb),
  ('eed0590a-31cc-5599-9663-b9034997526f', '41816686', '10.3389/fmicb.2026.1734749', 'Breaking the outer membrane barrier: structure, targets, and antimicrobial strategies for Gram-negative bacteria', 'Multidrug resistance in Gram-negative bacteria has become a significant global public health challenge, threatening human health and clinical treatment outcomes. The unique outer membrane structure of these pathogens greatly limits antibiotic penetration, serving as the core mechanism of resistance. This paper systematically analyses antimicrobial strategies targeting the outer membrane of Gram-negative bacteria, mainly including: (1) directly disrupting the outer membrane structure and enhancing drug permeability; (2) inhibiting the biosynthesis or transport pathways of key outer membrane components; (3) using natural pathways to facilitate drug entry into the cell; (4) inhibiting efflux pumps to block efflux functions; (5) optimizing the physicochemical properties of drugs to enhance outer membrane permeability and using nanotechnology to develop new drug delivery systems. In recent years, BAM complex inhibitors like darobactin and xenorceptides have efficiently blocked the assembly of outer membrane proteins through a novel mechanism and exhibited excellent broad-spectrum antibacterial activity. Iron carrier-conjugated drugs like cefiderocol have also successfully transitioned to clinical use, showing significant efficacy in treating infections caused by various multidrug-resistant bacteria. Despite promising strategies targeting the outer membrane, drug development faces challenges, such as poor selectivity, potential toxicity, and evolving resistance mechanisms. Future research must delve deeper into the biosynthesis and regulatory mechanisms of the outer membrane, aiming to develop more selective and safer innovative antimicrobial drugs and delivery systems to effectively combat the growing threat of multidrug-resistant Gram-negative bacterial infections.', 2026, 'europepmc', '{"authorString": "Xu F, Xie Y, Yu W, Wang Z.", "journal": null}'::jsonb),
  ('4db0cde5-d1f9-51fb-a16a-0e7338b6a33e', '42059811', '10.1128/aac.01832-25', 'Determination of frequency of spontaneous resistance for gepotidacin and levofloxacin against a collection of gram-positive and gram-negative organisms', 'Gepotidacin is a novel, bactericidal, first-in-class triazaacenaphthylene antimicrobial recently approved by the Food and Drug Administration (FDA) and Medicines and Healthcare products Regulatory Agency for the treatment of uncomplicated urinary tract infections (uUTI) and by the FDA for uncomplicated urogenital gonorrhea. Gepotidacin selectively inhibits type II topoisomerases involved in bacterial DNA replication by a distinct binding site and novel mechanism of action, conferring <i>in vitro</i> activity against most uropathogens, including those resistant to current antimicrobials. This study evaluated the potential of gepotidacin to select for spontaneous resistance in <i>Citrobacter freundii</i>, <i>Enterobacter cloacae</i> species complex, <i>Klebsiella aerogenes</i>, <i>Klebsiella pneumoniae</i>, <i>Proteus mirabilis</i>, <i>Providencia rettgeri</i>, <i>Enterococcus faecalis</i>, and <i>Staphylococcus saprophyticus</i> clinical isolates. Mutant frequencies ranged from 6.1 × 10<sup>-8</sup> to <2.5 × 10<sup>-10</sup> at 4× gepotidacin MIC concentrations, and no mutant isolates were recovered at 10× gepotidacin MIC concentrations. No target gene-specific (<i>gyrA</i>, <i>gyrB</i>, <i>parC</i>, <i>parE</i>) cross-resistance was observed with any of the comparators tested. As gepotidacin target site mutations in <i>gyrA/B</i> were only found in <i>Enterococcus faecalis</i>, repressor inactivation or activator dysregulation mutations in efflux pumps were identified as possible mechanisms of reduced susceptibility in the Gram-negative isolates. Further investigation is needed into the relevance of these resistance mechanisms, the clinical significance of these findings, and whether there are any potential fitness costs of decreased gepotidacin susceptibility.', 2026, 'europepmc', '{"authorString": "Morgan GM, Kimbrough JH, Karr MH, Thompson J, West J, Castanheira M, Arends SJR, Scangarella-Oman N.", "journal": null}'::jsonb),
  ('1163dd96-bae8-55a3-9008-fed8d612c1ba', '42196587', '10.3390/ijms27104610', 'Synergy Between the Auranofin Analogue PEt&lt;sub&gt;3&lt;/sub&gt;AuCl and Membrane Disruptors, Efflux-Pump Blockers, and Glutathione-Depletors Uncovers Tolerance Pathways in &lt;i&gt;Pseudomonas aeruginosa&lt;/i&gt;', 'Auranofin (AF), an FDA-approved drug for rheumatoid arthritis, exhibits strong antibacterial activity against Gram-positive bacteria, while Gram-negative species remain largely tolerant. This study assessed the antimicrobial activity of AF and three analogues against clinically relevant Gram-negative pathogens and explored tolerance mechanisms in <i>Pseudomonas aeruginosa</i>. Broth microdilution assays were performed on reference strains and clinical isolates of <i>Escherichia coli</i>, <i>Klebsiella pneumoniae</i>, and <i>P. aeruginosa</i>. Synergy studies with the most active analogue, PEt<sub>3</sub>AuCl (AF-Cl), were conducted against <i>P. aeruginosa</i> using polymyxin B (PMB), two efflux-pump inhibitors, and two glutathione (GSH) depletors. Gold compounds showed MICs between 4 and >64 µg/mL, with AF-Cl displaying the highest activity. AF-Cl activity was markedly enhanced by PMB and efflux-pump inhibitors, indicating that outer membrane permeability and efflux contribute to tolerance. Additionally, GSH depletion significantly potentiated AF-Cl, implicating redox homeostasis in resistance. Overall, AF-Cl shows potential against Gram-negative bacteria when combined with agents targeting membrane integrity, efflux systems, or redox balance, supporting combinatorial strategies to overcome resistance in <i>P. aeruginosa</i> and related pathogens.', 2026, 'europepmc', '{"authorString": "Amato B, Mazzantini D, de Azevedo-Fran\u00e7a JA, Maisetta G, Ghelardi E, Esin S, Messori L, Batoni G.", "journal": null}'::jsonb),
  ('aa53784c-da64-5857-b14c-3f545f4e1673', '41263575', '10.1128/mmbr.00278-24', 'Beyond antibiotic resistance: evidence for resistance-nodulation-division (RND) efflux pumps as virulence determinants', 'SUMMARYEarly in evolution, cells acquired the ability to use energy to export waste and toxic products against a concentration gradient. In Gram-negative bacteria, the resistance-nodulation-cell division (RND) superfamily of multi-subunit efflux pumps transport toxic molecules to the extracellular milieu. RND efflux pumps require cell-membrane proton motive force to export a wide range of substrates. Within the RND superfamily, Hydrophobe/Amphiphile Efflux 1 (HAE-1) family members have been studied extensively for their critical role in exporting structurally diverse antibiotics and, consequently, their contributions to multidrug resistance. However, HAE-1 RND efflux pumps are also required for pathogen survival in the mammalian host when antibiotics are absent. Here, we investigate the role of HAE-1 RND efflux pumps as virulence determinants. We analyze the genetic evidence that Gram-negative bacterial pathogens require HAE-1 RND efflux pumps to cause infection and briefly discuss the development of therapeutic and prophylactic approaches to interfere with HAE-1 RND efflux pump activity as a complement to existing antibiotics.', 2025, 'europepmc', '{"authorString": "Detweiler CS, Alav I.", "journal": null}'::jsonb),
  ('4bb1f384-b09b-5f03-bb45-f3678df2152a', '42056714', '10.1080/21505594.2026.2664980', '&lt;i&gt;Acinetobacter baumannii&lt;/i&gt;: Mechanisms of antibiotic resistance, quorum sensing regulation, and current therapeutic strategies', '<i>Acinetobacter baumannii</i> has emerged as a major global pathogen due to extensive resistance to last-resort antimicrobials, a high burden of nosocomial infections, and increasing community-acquired cases. Its adaptability is driven by diverse resistance mechanisms, including β-lactamase production, aminoglycoside-modifying enzymes, efflux pump overexpression, target-site mutations, and lipid A remodeling, all of which limit treatment options and worsen clinical outcomes. Pathogenicity is further enhanced by quorum-sensing systems, particularly AbaI/AbaR, which regulate biofilm formation, virulence, and antimicrobial tolerance. Despite extensive research, resistance, quorum sensing, and therapeutic strategies are often examined separately, limiting mechanistic understanding. This review integrates current evidence on the interplay between resistance evolution, quorum sensing, and biofilm persistence, linking these to therapeutic vulnerabilities. It further evaluates emerging interventions, including optimized antibiotic combinations, immunomodulation, drug repurposing, bacteriophage therapy, and alternative approaches, such as antimicrobial peptides, phytochemicals, nanotechnology, and photodynamic therapy to inform improved treatment strategies.', 2026, 'europepmc', '{"authorString": "Fortaleza JAG, Cabuhat KSP, Ong CJN, Mortel FA, Bacalzo GD, Nuevo JJM.", "journal": null}'::jsonb),
  ('e8ef19b7-c371-5b77-b932-b544608642dd', '41848420', '10.1080/14756366.2026.2640718', 'Inhibition of prolyl-tRNA synthetase and efflux pumps as a dual-targeting strategy against multidrug-resistant bacteria', 'Aminoacyl-tRNA synthetases have been widely exploited as targets for antiparasitic and antifungal inhibitors; however, they have received little attention as targets in multidrug-resistant (MDR) bacteria. Here we describe the biochemical characterisation of Prolyl-tRNA synthetase from <i>Klebsiella pneumoniae</i> (KpProRS), highlighting its ligase and proofreading activities. Distinct classes of ProRS inhibitors were evaluated against KpProRS but only halofuginone (HF) strongly modulated KpProRS activity. A new HF analog (Cpd-6) was developed and exhibited superior inhibitory activity against KpProRS relative to HF but low efficacy against MDR <i>K. pneumoniae</i>, despite good antimicrobial activity against <i>Escherichia coli</i> and <i>Staphylococcus aureus.</i> Further studies revealed that Cpd-6 resistance in <i>K. pneumonia</i> is mainly mediated by <i>AcrAB</i> efflux pump activity, which could be counteracted by efflux pump inhibitors. These findings therefore reinforce KpProRS as a target for antimicrobial development and highlight the therapeutic potential of combining HF analogues with efflux pump inhibitors to fight Gram-negative MDR pathogens.', 2026, 'europepmc', '{"authorString": "Tambascia C, Silva JC, Dos Reis BC, Camilo CFS, Tairum Junior CA, Hancio T, Correia VG, Pilli RA, de Godoy AS, Laleu B, Sfor\u00e7a ML, Rocco SA, Benedetti CE, Mercaldi GF.", "journal": null}'::jsonb),
  ('5061acd8-0927-57ef-97f4-fa68f65be9be', '41321948', '10.7717/peerj.20360', 'Efflux systems driving resistance and virulence across biological domains', '<h4>Background</h4>Efflux pumps (EPs) are key contributors to multidrug resistance (MDR) in bacteria, fungi, and cancer cells. These membrane proteins actively extrude a variety of therapeutic agents, reducing their intracellular concentration and thus compromising the efficacy of treatment. Beyond resistance, EPs are also involved in virulence, biofilm formation, immune evasion, and environmental persistence.<h4>Aim</h4>This review aimed to provide a comprehensive and critical synthesis of the role of efflux pumps in antimicrobial and antitumoral resistance, as well as their contribution to virulence and persistence across biological domains.<h4>Methodology</h4>A narrative review was conducted following a structured search strategy in PubMed, Scopus, and Web of Science using combinations of terms related to efflux systems, efflux pumps, resistance mechanisms, virulence factors, detection methods, and inhibitors. The review integrates data from <i>in vitro</i>, <i>in silico</i>, and clinical studies, including both classical detection strategies and emerging technologies such as clustered regularly interspaced short palindromic repeats (CRISPR)-based modulation, biosensors, and microfluidics.<h4>Results</h4>Efflux pumps from different families (<i>e.g.</i>, resistance-nodulation-division (RND), ATP-binding cassette (ABC), major facilitator superfamily (MFS)) are implicated in the active extrusion of antimicrobial agents, facilitating MDR and treatment failure in pathogens such as <i>E. coli</i>, <i>P. aeruginosa</i>, <i>M. tuberculosis</i>, <i>Candida albicans</i>, and cancer cells. EPs also regulate biofilm formation, virulence factor secretion, and metabolic adaptation. Classical methods for detecting efflux (<i>e.g.</i>, minimum inhibitory concentration (MIC) shifts with inhibitors, fluorometric assays) have technical limitations, while novel technologies offer improved precision. Several natural and synthetic efflux pump inhibitors (EPIs) have demonstrated efficacy in preclinical studies, yet few have progressed to clinical use due to toxicity and pharmacokinetic barriers. CRISPR interference systems and combinatory therapies represent promising advances in overcoming EP-mediated resistance.<h4>Conclusion</h4>Efflux systems are central players in both drug resistance and pathogenicity. Although the development of effective EIs remains challenging, advances in molecular detection, gene editing, and drug design hold potential for translational breakthroughs. A deeper understanding of efflux dynamics across organisms is essential to develop adjuvant therapies and reduce the clinical impact of MDR.', 2025, 'europepmc', '{"authorString": "Almeida da Silva PE, Von Groll A, Ramis I, Reis AJ, Ramos D, Viveiros M.", "journal": null}'::jsonb),
  ('84ae9cba-185a-589e-9ede-0ecb194b6f22', '41779040', '10.1556/1886.2026.00004', 'Acquired resistance in Stenotrophomonas maltophilia: Mechanisms underlying the shift from multidrug to pandrug resistance', 'Stenotrophomonas maltophilia is an emerging multidrug-resistant (MDR) pathogen that primarily causes healthcare-associated infections. This bacterium employs two key resistance mechanisms-intrinsic and acquired-to withstand antimicrobial toxicity, facilitating its spread and persistence within healthcare settings. This review focuses on acquired resistance mechanisms in S. maltophilia, highlighting genetic mutations and gene acquisition through horizontal gene transfer (HGT). Mutations that confer antimicrobial resistance commonly occur in drug targets (e.g., gyrA and parC, which encode DNA gyrase and topoisomerase IV, respectively), drug uptake systems, ribosomal proteins, metabolic enzymes, and more importantly, transcriptional regulators of multidrug efflux systems. These mutations can lead to resistance against the first-line treatments for S. maltophilia infections, including trimethoprim/sulfamethoxazole, levofloxacin, cefiderocol, and minocycline. The acquisition of resistomes via HGT also occur in S. maltophilia. Resistance genes, such as those encoding sulfonamide resistance (sul), trimethoprim resistance (dfr), quinolone resistance (qnr), aminoglycoside-modifying enzymes, and multidrug/biocide efflux pumps can be transferred from neighboring microbial communities through various genetic vectors, including insertion sequences, transposons, gene cassettes/integrons, and conjugative plasmids. Intrinsic resistance, combined with acquired resistance, can transform S. maltophilia from an MDR pathogen into an extensively drug-resistant or even pandrug-resistant strain, thus further complicating its treatment and management.', 2026, 'europepmc', '{"authorString": "Vattanaviboon P, Dulyayangkul P, Tipanyo P, Mongkolsuk S, Charoenlap N.", "journal": null}'::jsonb),
  ('2500c0d0-14a3-5bd9-9ac1-c00816f6ea75', '41521891', '10.1099/mgen.0.001593', 'The Resistance-Nodulation-Division efflux pump EefABC is highly conserved within lineages of &lt;i&gt;E. coli&lt;/i&gt; commonly associated with infection', 'Resistance-nodulation-division (RND) efflux pumps confer multidrug resistance in Gram-negative bacteria and are critical for many physiological functions including virulence and biofilm formation. The common <i>Escherichia coli</i> laboratory strain, K-12 MG1655, has six recognized RND transporters (AcrB, AcrD, AcrF, CusA, MdtBC and MdtF). However, by studying >20,000 <i>E</i>. <i>coli</i> assemblies, we show that <i>E. coli</i> belonging to phylogroups B2, D, E, F and G, which are commonly associated with infection, possess an additional, seventh RND transporter, EefB. It is found in a five-gene operon, <i>eefRABCD</i>, which also encodes a TetR family transcription factor, a periplasmic adapter protein, an outer membrane factor and major facilitator superfamily pump. In contrast, <i>E. coli</i> from phylogroups A, B1 and C, generally containing environmental/commensal strains, do not encode the operon. Where the <i>eefRABCD</i> operon is present, it was highly conserved. In fact, conservation levels were comparable to that of the major RND efflux system AcrAB-TolC, suggesting an important biological function. Protein modelling shows that this pump is distinct from endogenous <i>E. coli</i> RND systems with unique structural features. However, unlike other RND efflux systems, EefABC does not appear to transport antimicrobials and instead may be important for infection or survival in the host environment.', 2026, 'europepmc', '{"authorString": "Pugh HL, Darby EM, Burgess L, Colclough AL, John AM, Dunn S, Connor C, Perry EA, McNally A, Bavro VN, Blair JMA.", "journal": null}'::jsonb),
  ('c3285d7c-e796-5027-af74-946af6f919d3', '41473217', '10.1155/cjid/9591804', 'Outsmarting Nightmare: Drug Resistance in &lt;i&gt;Acinetobacter baumannii&lt;/i&gt;', '<i>Acinetobacter baumannii</i> is a critical nosocomial pathogen recognized by the WHO as a top-priority threat due to its extensive drug resistance, particularly in carbapenem-resistant <i>Acinetobacter baumannii</i> (CRAB) strains. According to recent CDC reports, CRAB is one of the most urgent causes of hospital-acquired infections, driving longer hospital stays, higher costs, and mortality. This pathogen employs multiple resistance mechanisms, including efflux pumps, porins like OmpA, making it highly difficult to treat. Resistance is further shaped by β-lactamases, integrons, and mobile genetic elements. The emergence of MDR, XDR, and PDR strains signals the looming postantibiotic era, where conventional therapies are increasingly ineffective. While several reviews have provided in-depth analyses of individual mechanisms and some comprehensive overviews, this work provides a broad overview of resistance strategies and genetic determinants, including <i>tet(A/B)</i>, <i>cmlA</i>, and <i>mdfA</i>. Importantly, we also highlight emerging alternatives such as novel emergent phage therapy (NEPT), which proactively counters antiphage resistance and nanoparticles (CNPs), which resensitize resistant isolates and enhance antibiotic efficacy. By combining mechanistic insights with emerging interventions, this review provides a comprehensive perspective on CRAB resistance and highlights research priorities for mitigating its global threat.', 2025, 'europepmc', '{"authorString": "Praveen A, Sinduja A, Yadav MK, Sharma D, Singh A.", "journal": null}'::jsonb),
  ('1eef8b62-8841-5052-8d31-5af11decd4d5', '41802016', '10.1371/journal.ppat.1014031', 'RND-mediated efflux couples antimicrobial resistance and hypervirulence in contemporary Vibrio cholerae', 'The prevailing view in bacterial pathogenesis is that antimicrobial resistance and virulence are constrained by evolutionary trade-offs, with resistance mechanisms imposing fitness costs that attenuate pathogenic potential. Herein we document that contemporary Vibrio cholerae clinical isolates from the ongoing seventh pandemic have circumvented this paradigm by coupling multidrug resistance with hypervirulence. We examined five geographically diverse Wave 3 isolates collected between 2017 and 2019 and compared them to early pandemic strains. These contemporary isolates exhibited both broad-spectrum antimicrobial resistance and markedly enhanced colonization capacity in the infant mouse model. Phylogenetic analysis of 67 O1 El Tor genomes spanning 1960-2019 confirmed that the isolates cluster within a representative Wave 3 sublineage. We identified the VexB RND efflux pump as a mediator of this coupled phenotype. Elevated vexB expression in the contemporary isolates conferred resistance to multiple antibiotic classes, while vexB inactivation simultaneously impaired resistance and colonization. This dual function was not observed in early pandemic strains, consistent with a recent evolutionary adaptation. VexB-mediated hypervirulence occurred through multiple pathways independent of cholera toxin and toxin-coregulated pilus production levels. VexB deletion impaired bacterial adherence to intestinal epithelial cells, impaired motility, and increased susceptibility to membrane-active antimicrobials. In contrast, laboratory evolution under antibiotic pressure alone generated resistant but avirulent strains, demonstrating that complex selective forces in nature enabled the co-optimization of resistance and virulence. These findings establish VexB as a molecular link between antimicrobial resistance and hypervirulence in pandemic V. cholerae, highlighting efflux pumps as dual-function therapeutic targets whose inhibition could both restore antibiotic activity and attenuate disease.', 2026, 'europepmc', '{"authorString": "Weng Y, Bina XR, Van Allen ME, Bina JE.", "journal": null}'::jsonb),
  ('ac472943-9ad7-5710-b1cd-821c94ae0971', '41767952', '10.1002/mlf2.70051', 'Antibiotic resistance mediated by site-specific mutations in the multidrug efflux transporter CmeB of zoonotic pathogen &lt;i&gt;Campylobacter&lt;/i&gt;', 'The resistance‒nodulation‒division (RND) family of multidrug efflux transporters is widely distributed in Gram-negative bacteria. Although their roles in mediating antibiotic resistance have been well known, our understanding of how they are altered to augment bacterial adaptation to antibiotic selection remains at an infancy stage. Here, we report the identification of a mutation-based mechanism that empowers the function of the CmeB efflux protein, an RND-type transporter in the zoonotic pathogen <i>Campylobacte</i>r. During our surveillance study, we identified <i>Campylobacter</i> isolates that were phenotypically resistant to florfenicol but lacked known florfenicol resistance mechanisms. Using natural transformation and whole genome sequencing, we first linked the phenotype to sequence polymorphisms in the <i>cmeB</i> and subsequently demonstrated that both the T136A and M292I mutations in CmeB are required for the resistance phenotype. The mutations elevated <i>Campylobacter</i> resistance to florfenicol, ciprofloxacin, and other classes of antimicrobial agents. Structural modeling and molecular dynamics simulations revealed that the two residues were localized in the drug-binding pocket of CmeB, and the T136A and M292I substitutions enhanced hydrophobic interactions, stabilized CmeB-antibiotic binding, and lessened steric hindrance in the drug-binding pocket, thereby facilitating antibiotic extrusion by CmeB. Analysis of the <i>Campylobacter</i> genomic sequences deposited in the NCBI database revealed that T136A- and M292I-harboring isolates were found in 35 different countries and associated with various host species, indicating the widespread distribution and clinical relevance of the two mutations. Together, these results identified a new mechanism underlying CmeB-mediated multidrug resistance and provide a potential target for clinical surveillance of antibiotic-resistant <i>Campylobacter</i>.', 2026, 'europepmc', '{"authorString": "Lin X, Zhao M, Gan J, Li H, He M, Yang F, Wen R, Zhang T, Zhou Q, Wu K, Li J, Hou C, Cao Y, Wang H, Tang Y.", "journal": null}'::jsonb),
  ('60c74978-bb2b-5c4f-9475-de809f92baf5', '41898562', '10.3390/ijms27062702', 'From Polyphenols to β-Lactamases: Multitarget Strategies to Defeat Severe Resistance', 'Antimicrobial resistance (AMR) is one of the most pressing global public health challenges, compromising the effectiveness of standard antibiotic therapies and increasing morbidity, mortality, and healthcare costs. The scarcity of new antibiotics has driven research into alternative strategies to restore or enhance the effectiveness of existing drugs. Natural compounds, including polyphenols, alkaloids, terpenes and terpenoids, antimicrobial peptides, and microbial secondary metabolites, exhibit multitarget activities such as membrane disruption, efflux pump inhibition, biofilm suppression, and quorum sensing interference. In parallel, synthetic and semi-synthetic small-molecule inhibitors have been rationally designed to target specific resistance determinants, including β-lactamases, efflux systems, quorum sensing pathways, and stress-induced mutagenesis mechanisms such as the SOS response and DNA repair processes. These agents act as adjuvants, restoring susceptibility or reducing bacterial virulence without exerting strong selective pressure. The integration of natural bioactive compounds and targeted small-molecule inhibitors represents a promising complementary strategy for conventional antibiotics. Further pharmacological and clinical investigations are required to translate these approaches into effective tools within antimicrobial stewardship programs and broader public health strategies aimed at mitigating the global burden of AMR. This narrative review analyses the recent literature on natural compounds and synthetic or semi-synthetic small-molecule inhibitors with documented activity against antimicrobial resistance mechanisms.', 2026, 'europepmc', '{"authorString": "Nappa M, Santoro E, Manente R, Cianciulli A, Moccia G, De Caro F, Capunzo M, Boccia G.", "journal": null}'::jsonb),
  ('42a8fc2b-a250-55d8-9040-b4adb0d1d85c', '42163991', '10.1016/j.engmic.2026.100273', 'Herbal extracts as antibiotic adjuvants against ESKAPE pathogens: mechanisms and therapeutic potential', 'The escalating crisis of antimicrobial resistance, particularly driven by ESKAPE pathogens, poses a serious threat to global public health. With the stagnant pipeline of novel antibiotic discovery, repurposing herbal extracts as antibiotic adjuvants to revive existing therapies is a promising strategy. This review systematically elaborates the multi-faceted mechanisms by which herbal extracts and their bioactive constituents counteract multi-drug resistance in ESKAPE pathogens. These mechanisms include the inhibition of antibiotic-degrading enzymes, alteration of bacterial membrane permeability to facilitate antibiotic uptake, blockade of major efflux pumps that expel multiple drug classes, and counteraction of antibiotic target modification. Furthermore, the roles of phytochemicals in inhibiting and dispersing biofilms, attenuating virulence factors, disrupting quorum sensing, and promoting reactive oxygen species accumulation are discussed. Despite the potent synergistic potential demonstrated by various lead compounds (such as andrographolide, quercetin, berberine, thymol, curcumin, eugenol, and oleanolic acid) in preclinical models, their progression through the translational pipeline is frequently hindered by inconsistent manufacturing standards and the inherent complexity of elucidating their polypharmacological mechanisms. Advancing the clinical utility of these herbal adjuvants necessitates a multidimensional approach, including artificial intelligence-driven screening, in-depth mechanistic studies of multi-component synergy, and comprehensive clinical assessments. Accordingly, this review aimed to establish a rigorous foundation for designing next-generation anti-infective therapies based on herb-antibiotic synergy.', 2026, 'europepmc', '{"authorString": "Ma H, Wang J, Zhang F, Gu L, Hu W, Wang C.", "journal": null}'::jsonb),
  ('a84a3389-fa12-5085-a5c6-a9155b544852', '41667237', '10.1111/apm.70161', 'In-Silico Characterisation of Burkholderia pseudomallei K96243 Pathogenic Islands: Unveiling Novel Targets for Therapeutic Development', 'Burkholderia pseudomallei is a deadly bacterium responsible for melioidosis, which is challenging to treat because of its antibiotic resistance and ability to evade the immune response. This study is focused on in silico analysis to identify novel drug targets. The B. pseudomallei K96243 strain, we have identified seven pathogenicity islands with 138 genes. Subsequent filtering based on criteria such as the data present, essentiality, lack of human homology, and uniqueness narrowed this to 24 promising targets, with eight top candidates. These include proteins involved in energy production (ctaB, BPSL1454, BPSS0086, petB, BPSL1260 and BPSL1259), immune evasion (BPSL1655 and BPSS1780), and the porin efflux pump. Computational interaction analysis revealed a connection between these targets and human immune and respiratory pathways. Prominently, all eight potential drug target candidates showed no homology to human proteins, highlighting their promising role in drug development against melioidosis. This work provides an important framework for identifying novel therapeutics and vaccines against B. pseudomallei.', 2026, 'europepmc', '{"authorString": "Verma N, Srivastava A, Sharma S, Agarwal V.", "journal": null}'::jsonb),
  ('2ff76960-5cd4-5cf6-8de4-5ffa0cb55bec', '42333284', '10.2147/ijn.s617238', 'Development and Evaluation of Liposomal Nanobiotics for Combating Antibiotic Resistance Among Enterobacteriaceae', '<h4>Background</h4>The increasing prevalence of antimicrobial-resistant bacteria, such as <i>Escherichia coli, Klebsiella pneumoniae</i>, and non-typhoidal <i>Salmonella</i>, poses a significant healthcare problem, leading to increased mortality. Liposomal nanocarriers have already shown their potential in overcoming resistance and improving antibiotic delivery.<h4>Methods</h4>In this study, liposome-based nanocarriers encapsulating conventional antibiotics were developed, characterised and evaluated for their antibacterial efficacy and interactions with bacteria. The liposomal nanobiotics were prepared using the thin-film hydration method and loaded with antibiotics.<h4>Results</h4>The prepared nanobiotics of tetracycline, chloramphenicol and nalidixic acid showed average particle size of 120-190 nm and entrapment ranging between 30% and 85% for the antibiotics used. Furthermore, the formulations exhibited minimal cytotoxic effects on HEK293 cells, indicating favourable biocompatibility. Compared to the free antibiotics the nanobiotics demonstrated significantly enhanced antibacterial activity against MDR isolates. The time kill curves showed significant reduction in viable bacterial count, while in vitro release profile showed sustained release of the encapsulated liposomes around 85% within 24 hours. The TEM analysis and PI/calceinAM assay demonstrated effective liposme-bacterial interaction and enhanced intracellular delivery of the encapsulated antibiotics. Further, the analysis of the efflux-pump associated genes showed impact of nanobiotic formulations on efflux pump gene expressions and suggests a role in mitigating the resistance mechanism. Also, antibiotics encapsulated in liposomes significantly reduced the bacterial load across all conditions in the food-spiking experiment with enhanced antibiotic delivery.<h4>Conclusion</h4>The liposomal formulation of tetracycline, chloramphenicol and nalidixic acid showed better physicochemical properties, sustained release profile and increased antibacterial activity against MDR bacterial isolates compared to free drug. Overall findings suggest that encapsulation enhances the therapeutic potential of the conventional antibiotics and can be a promising strategy to overcome the multi-drug resistance in bacteria.', 2026, 'europepmc', '{"authorString": "Devi T B, K V DF, Kini S, Deekshit VK.", "journal": null}'::jsonb),
  ('52dcc0fd-02d1-5fc2-af57-857c86359460', '42041382', '10.3390/antibiotics15040419', 'How Glyphosate and Its Derivatives Influence Antimicrobial Resistance Emergence and Transmission: A One Health Perspective', '<b>Background/Objectives:</b> Glyphosate-based formulations are globally pervasive pollutants increasingly recognized as potential contributors to antimicrobial resistance (AMR) in environmental microbiomes. Although glyphosate is designed to inhibit plant 5-enolpyruvylshikimate-3-phosphate synthase, it also affects microbial metabolism, stress response, and genetic exchange. This review synthesizes the pathways through which glyphosate, its metabolite aminomethylphosphonic acid (AMPA), and commercial mixtures influence resistance-associated phenotypes and the dissemination of antibiotic resistance (ABR). <b>Methods:</b> A critical synthesis of the literature was conducted to evaluate the mechanistic and ecological interactions between glyphosate exposure and bacterial resistance in soil, aquatic, and host-associated microbiomes. <b>Results:</b> Experimental evidence showed that sublethal glyphosate exposure induced oxidative stress, altered membrane permeability, activated multidrug efflux pumps, and promoted tolerance phenotypes that could modify antibiotic susceptibility. It also enhances mutation rates and horizontal gene transfer processes associated with the emergence of resistance under controlled conditions. At the community level, glyphosate exposure is associated with microbiome restructuring and enrichment of resistance determinants, often without major shifts in overall diversity of the microbiome. These effects have been reported at environmentally relevant concentrations, although the evidence remains largely derived from laboratory and mesocosm studies. <b>Conclusions:</b> Glyphosate acts as both a biochemical modulator of resistance-related phenotypes and an environmental selective pressure that shapes microbial communities. Its widespread use and environmental persistence position it as a context-dependent contributor to the emergence and dissemination of AMR through interacting mechanistic and ecological pathways. Integrating AMR endpoints into pesticide risk assessments and surveillance frameworks is warranted, in addition to expanded field-based validation.', 2026, 'europepmc', '{"authorString": "Malinoski L, Silva GG, Rodrigues LKI, Carneiro LF, Gomes MP.", "journal": null}'::jsonb),
  ('0750d8a8-0c22-5f66-97a9-5d29e2cad191', '41246003', '10.2147/idr.s541348', 'Genomic Characterization of a Fluoroquinolone Intermediate Resistance &lt;i&gt;Herbaspirillum&lt;/i&gt; sp. Strain HhutSZ1 Rarely Causing Bacteremia', '<h4>Purpose</h4>This study aims to conduct a whole-genome analysis of the isolated strain HhutSZ1, providing more reliable clinical experience for the treatment of patients infected with such bacteria.<h4>Patients and methods</h4>A patient with IgA nephropathy failed to respond to treatment with ciprofloxacin for an infection. A rare strain of <i>Herbaspirillum</i> was isolated from the patient''s blood. The VITEK MS Matrix-Assisted Laser Desorption/Ionization Time-of-Flight Mass Spectrometry (MALDI-TOF MS) System and VITEK 2 Automated Microbial Identification System were used to conduct a preliminary identification and antibiotic susceptibility tests. Then we performed whole-genome sequencing of this strain along with comparative genomic analysis.<h4>Results</h4>VITEK 2 System identified HhutSZ1 as <i>Burkholderia cepacia</i>, while the VITEK MS System identified it as <i>Herbaspirillum huttiense</i> with a high confidence coefficient. The phylogenetic tree based on the 16S rRNA gene showed that HhutSZ1 belonged to the genus <i>Herbaspirillum</i>. Average Nucleotide Identity (ANI) analysis showed that the scores of this strain compared with other <i>Herbaspirillum huttiense</i> strains were all lower than 95, confirming that this strain did not belong to <i>Herbaspirillum huttiense</i>. The patient''s infection failed to resolve despite ciprofloxacin treatment. Subsequent antimicrobial susceptibility testing revealed that HhutSZ1 exhibited intermediate resistance to ciprofloxacin, which is consistent with the clinical treatment failure. Six genes were detected in the Comprehensive Antibiotic Resistance Database (CARD). And among them, five RND family efflux pump genes resistant to fluoroquinolone were all located on chromosomes.<h4>Conclusion</h4>For the genus <i>Herbaspirillum</i>, mass spectrometry identification cannot accurately identify the species. The analysis based on 16s rRNA combined with ANI can be more accurate. Some <i>Herbaspirillum spp</i> may have inherent resistance to fluoroquinolone antibiotics. In conclusion, our findings suggest that the low detection rate and low drug resistance of this strain cannot be overlooked, and the study provides valuable clinical insight for managing infections in immunocompromised patients.', 2025, 'europepmc', '{"authorString": "Luo Y, Li T, Zhang S, Gu D, Fan B.", "journal": null}'::jsonb),
  ('12b63d16-fdcb-5ce6-9753-e0b635c944dc', '42024584', '10.1080/17460913.2026.2661231', 'The role of eravacycline in combating multidrug-resistant bacterial infections: insights into efficacy, emerging resistance, and clinical safety', 'The global rise of multidrug-resistant bacteria, including <i>carbapenem-resistant Enterobacterales (CRE)</i>, <i>carbapenem-resistant Acinetobacter baumannii (CRAB)</i>, <i>methicillin-resistant Staphylococcus aureus (MRSA)</i> and <i>Vancomycin-Resistant Enterococcus spp</i> (<i>VRE</i>), poses a major public health threat and complicates treatment. Eravacycline, a new synthetic fluorocycline antibiotic, shows strong in vitro effectiveness against various multidrug-resistant (MDR) Gram-positive and Gram-negative bacteria and anaerobes. Its unique structural modifications help it overcome common tetracycline resistance mechanisms. Real-world data show eravacycline achieves high cure and survival rates with low recurrence for infections by <i>CRE</i>, <i>CRAB</i>, <i>MRSA</i>, and <i>VRE</i>, though its effectiveness against <i>Pseudomonas aeruginosa</i> and <i>Burkholderia cepacia</i> is limited. Key resistance mechanisms in clinical isolates include efflux pump upregulation, ribosomal mutations, and plasmid-mediated <i>tet(X)</i> genes. Eravacycline is generally safe, causing fewer gastrointestinal issues than tigecycline and less nephrotoxicity than polymyxins. It doesn''t require dosage adjustments for renal or mild-to-moderate hepatic impairment. Eravacycline is vital for treating MDR infections when traditional therapies fail. However, it is currently approved by the U.S. Food and Drug Administration specifically for parenteral administration in the treatment of complicated intra-abdominal infections. Therefore, more large-scale trials are needed to confirm its effectiveness, optimize combination therapies, and further address the MDR crisis.', 2026, 'europepmc', '{"authorString": "Liang D, Yan Y, Wu G, Huang J, Xie M, Tan Y, Wu J.", "journal": null}'::jsonb),
  ('485abc67-2018-5bdd-89c0-0886e2b95613', '41635966', '10.1002/cns.70724', 'Double-Duty Drugs: Repositioning Antipsychotics to Combat Bacterial Infections', '<h4>Introduction</h4>This article provides a comprehensive review of the antibacterial properties of antipsychotics, exploring proposed pathways and mechanisms of action. While experimental evidence supports certain mechanisms, such as efflux pump inhibition, others, including the impact on the respiratory chain in M. tuberculosis and cell wall inhibition, remain insufficiently substantiated.<h4>Methods</h4>Current research primarily relies on in vitro experiments, with limited exploration of in vivo effects. The influence of antipsychotics on gut microbiota poses a significant concern, as alterations may lead to dysbiosis, which has been linked to various illnesses. Additionally, antimicrobial drugs can exert selective pressure, fostering resistance in bacterial strains.<h4>Results</h4>Repositioning antipsychotics as antimicrobials is further complicated by the need for higher doses than those approved for therapeutic use in humans, raising safety concerns. The use of antipsychotics in non-psychotic populations is particularly problematic due to a lack of proven efficacy and potential adverse effects, such as metabolic disturbances, movement disorders, and sleep issues.<h4>Conclusions</h4>These challenges highlight the need for extensive in vivo and clinical studies to evaluate the antibacterial potential of antipsychotics, ensuring safety and efficacy. Careful monitoring and a balanced risk-benefit analysis are essential when considering antipsychotics for antimicrobial purposes.', 2026, 'europepmc', '{"authorString": "Faraji N, Abavisani M, Ebadpour N, Karav S, Kesharwani P, Sahebkar A.", "journal": null}'::jsonb),
  ('08260d26-53b7-5adc-af9e-fea58b2798be', '42039799', '10.3389/fmicb.2026.1779022', 'Bacterial secondary metabolites as resistance-modifying adjuvants: microbial origins, molecular mechanisms, and translational relevance', 'The accelerating crisis of antimicrobial resistance (AMR) necessitates strategies that extend beyond the continual discovery of new conventional antibiotics. Bacterial secondary metabolites, historically valued as sources of antimicrobial scaffolds, are increasingly recognized for their roles as resistance-modifying and anti-virulence agents. This review synthesizes key advances from 2020 to 2025 that reposition bacterial secondary metabolites as integral components of next-phase AMR intervention strategies. We examine their chemical and biosynthetic diversity, ecological functions, and molecular mechanisms of action, including efflux pump inhibition, <i>β</i>-lactamase suppression, interference with ribosomal protection, and disruption of biofilms and quorum-sensing networks. Mechanistic and evolutionary analyses are integrated to explain why many metabolites impose higher barriers to resistance development than single-target antibiotics. We further discuss contemporary discovery and optimization pipelines encompassing genome mining, multi-omics approaches, synthetic biology, and AI-assisted structure-activity modeling. Translational considerations are critically evaluated, with emphasis on pharmacokinetic and pharmacodynamic constraints, rational combination therapy design, preclinical validation, and emerging development pipelines. Regulatory, manufacturing, and commercialization challenges are addressed alongside opportunities enabled by nanocarrier delivery systems, microbiome-informed strategies, and personalized medicine. Overall, this review highlights bacterial secondary metabolites as evolution-resilient anti-resistance modalities capable of restoring and extending the efficacy of existing antibiotics, offering a pragmatic and mechanistically grounded path forward in combating AMR.', 2026, 'europepmc', '{"authorString": "Chigozie VU, Esimone CO.", "journal": null}'::jsonb),
  ('84b5ece2-c1c0-5007-b6ff-41c3398e4321', '42228388', '10.1099/mgen.0.001663', 'Whole-genome analysis of a novel &lt;i&gt;Pandoraea sputorum&lt;/i&gt; lineage causing high-mortality bloodstream infections', '<b>Background.</b> <i>Pandoraea sputorum</i> is an emerging multidrug-resistant pathogen primarily associated with cystic fibrosis. Bloodstream infections (BSIs) are rare but linked to high mortality. The genomic characteristics and evolutionary history of <i>P. sputorum</i> lineages causing BSIs remain poorly understood.<b>Methods.</b> We performed whole-genome sequencing on 18 <i>P</i>. <i>sputorum</i> isolates recovered from patients with BSIs in China between June 2022 and March 2024. Phylogenetic relationships were determined by core-genome SNP analysis, and the pan-genome was characterized using Roary. Antimicrobial resistance and virulence genes were identified using the CARD and VFDB databases. Evolutionary timescales were estimated using Bayesian molecular clock analysis.<b>Results.</b> The case fatality rate among patients was 27.8% (5 out of 18). Common clinical manifestations included fever (83.3%, 15 out of 18), productive cough (77.8%, 14 out of 18) and dyspnoea (61.1%, 11 out of 18). All isolates formed a distinct monophyletic lineage, genetically distant (>2,000 SNPs) from known <i>P. sputorum</i> strains but with minimal intra-lineage diversity (15-98 SNPs), indicating recent clonal expansion. The pan-genome was highly conserved, with core genes comprising 94.6% of the gene repertoire. All strains harboured core genome-encoded <i>ceoB</i> (efflux pump) and <i>OXA-155</i> (β-lactamase) genes, conferring resistance to multiple antimicrobials but remaining susceptible to imipenem. Bayesian analysis estimated the origin of this lineage in 2004 (95% highest posterior density: 2003.2-2005.8), with major diversification occurring between 2007 and 2018.<b>Conclusion.</b> We identified a novel, recently emerged and highly clonal lineage of <i>P. sputorum</i> associated with high-mortality BSIs. Its stable reservoir of core genome-encoded resistance mechanisms poses a significant therapeutic challenge. This lineage represents an emerging multidrug-resistant threat to public health, necessitating enhanced surveillance and infection control measures.', 2026, 'europepmc', '{"authorString": "Wu H, Liu L, Li S, Zhang P, Xing Z, Huang Q, Kuang D, Liu W, Chen C, Xia Q.", "journal": null}'::jsonb),
  ('98cd484b-e9b5-5361-b91f-c2f6b63908e0', '40861388', '10.12688/wellcomeopenres.24138.2', 'Case Report: Genetic evolution of &lt;i&gt;Burkholderia pseudomallei&lt;/i&gt; during treatment leading to antibiotic resistance and disease relapse', '<h4>Background</h4>Melioidosis is a significant yet neglected cause of sepsis in tropical regions, particularly in southeast Asia, with poor clinical outcomes. It is a growing threat with an expanding global footprint. The causative organism, <i>Burkholderia pseudomallei</i>, is intrinsically resistant to most first-line empiric antibiotic regimens, but acquired resistance to recommended antibiotics for this infection is uncommon. Nonetheless, the genetic determinants of resistance in this species remain poorly elucidated.<h4>Case presentation</h4>A 60-year-old farmer presented in septic shock to a hospital in Laos, and <i>B. pseudomallei</i> was grown from blood cultures. Following initial antibiotic treatment with meropenem and co-trimoxazole, his infection relapsed. Several subsequent <i>B. pseudomallei</i> isolates from the patient were resistant to multiple antibiotics, and whole genome sequencing demonstrated that this phenotype was associated with a novel 54-kb genomic deletion. This deletion, on chromosome 1, includes the 5'' end of <i>amrR</i> - which encodes a regulator of an efflux pump known to be important in conferring meropenem resistance - as well as 46 other genes, some of which have not been characterised. Treatment was targeted to the new antibiogram, requiring a further prolonged intravenous course and second-line oral eradication therapy. The patient made a full recovery.<h4>Conclusions</h4>Mutations in <i>Burkholderia pseudomallei</i> lead to increased virulence and drug resistance. Repeat microbiological sampling of patients who do not make clinical improvement as anticipated is essential, with repeat full antimicrobial susceptibility testing on subsequent isolates. Characterisation of drug-resistant mutants is required to understand mechanisms of resistance and to predict phenotypes from whole genome sequencing.', 2025, 'europepmc', '{"authorString": "Evans TJ, Keeratipusana C, Douangnouvong A, Phimolsarnnousith V, Sengdatka D, Chang K, Phommasone K, Chewapreecha C, Ashley EA, Batty EM.", "journal": null}'::jsonb),
  ('f87ac062-9a8b-52a5-875c-a0b0df345b45', '41490277', '10.1021/acsinfecdis.5c00722', 'Broad-Spectrum Naphthyl-Substituted Diaminoquinolines Inhibiting the AdeG Efflux Pump of &lt;i&gt;Acinetobacter baumannii&lt;/i&gt;', 'AdeFGH and AdeIJK, the two homologous multidrug efflux pumps of the resistance-nodulation-division superfamily of transporters, play distinct roles in <i>Acinetobacter baumannii</i> physiology and antibiotic resistance. Unlike ubiquitous AdeIJK, AdeFGH is strain-specific, typically expressed at low levels, and if overproduced, it enables resistance to a narrow spectrum of antibiotics, e.g., fluoroquinolones or chloramphenicol. In this study, we report that representatives of naphthyl-substituted diaminoquinolines targeting AdeIJK are also active against AdeFGH. We isolated AdeFGH-overproducing strains from the clinical AYE and Ab5075 isolates lacking AdeIJK and AdeABC pumps and demonstrated that these inhibitors are active in <i>A. baumannii</i> strains with different genetic backgrounds. The inhibitors potentiate the antibacterial activities of various antibiotics and enhance the bactericidal properties of the fluoroquinolones. We further analyzed how amino acid substitutions in the substrate translocation tunnels of AdeG affect the efflux properties of this pump and its sensitivity to inhibitors and compared them to the analogous substitutions in AdeJ. Our results suggest that the inhibitors engage similar contacts within the deep binding pockets of the two pumps but differ in their interactions in the entrance and the proximal binding sites. We conclude that the broad-spectrum activities of the diaminoquinolines as well as other inhibitors likely arise from the interactions within the deep-binding pockets, but their specificity is determined in the proximal-binding sites of the pumps.', 2026, 'europepmc', '{"authorString": "Tambat R, Sariyer AS, Sariyer E, Olvera M, Farjana M, D''Cunha N, Walker JK, Zgurskaya HI.", "journal": null}'::jsonb),
  ('c174244a-274a-56ba-b9d9-9e4d7c927570', '41543281', '10.1021/acsinfecdis.5c00760', 'Substrate Specificity Checkpoints of the Multidrug Efflux Pump MexF from &lt;i&gt;Pseudomonas aeruginosa&lt;/i&gt;', 'Multidrug efflux pumps of the resistance-nodulation-division (RND) superfamily are major contributors to antibiotic resistance in <i>Pseudomonas aeruginosa</i>. Among these, the MexEF-OprN system, when overproduced in clinical isolates, confers resistance to fluoroquinolones, trimethoprim, and chloramphenicol. The inner-membrane RND transporter MexF in this complex exhibits a relatively narrow substrate specificity and the molecular mechanisms underlying this specificity are still unclear. Here, we employed a combination of experimental and computational approaches to dissect the role of a major putative recognition/binding site, the Access pocket, in the substrate specificity of MexF. Mutations at four selected positions D132, P136, G626, and S729 altered resistance profiles and substrate specificity in a residue- and substrate-specific manner. Notably, substitutions at P136 enhanced efflux of most tested antibiotics, among which are 21 fluoroquinolones with different structures. Substitutions in S729, on the other hand, either enhanced or severely impaired MexF activity depending on the substitution. Antibiotic substrates were found to compete with a fluorescent probe for MexF efflux revealing overlapping binding determinants and shared translocation paths within the transporter. Ensemble docking and contact frequency analyses further demonstrated that mutations reshaped ligand binding preferences within the periplasmic cleft, modulating the probability of transition to the Deep pocket and subsequent extrusion. Our results demonstrate that MexF is optimized to trimethoprim-like compounds and single substitutions in key residues can dramatically change the substrate spectrum of this pump. These findings underline the importance of not only static binding contacts between substrates and a polyspecific transporter such as MexF but also spatial occupancy and pathway integrity in determining drug efflux efficiency.', 2026, 'europepmc', '{"authorString": "Uddin MR, Gervasoni S, Malloci G, Ruggerone P, Zgurskaya HI.", "journal": null}'::jsonb),
  ('698a0bf6-8ce7-560a-86d0-f22bcf3e0c9e', '42192724', '10.3390/antibiotics15050502', 'West Siberian Soil Resistome: Mobile Antibiotic Resistance in Agricultural Microbiomes', '<b>Background/Objectives:</b> Soil microbiomes in agroecosystems are natural reservoirs of antibiotic resistance genes (ARGs) and mobile genetic elements (MGEs), creating conditions for horizontal gene transfer (HGT) to clinically relevant bacteria. Southern West Siberia-a globally significant grain-producing region-lacks metagenomic characterization of its soil resistome. This study aimed to establish the first baseline profile of resistome and mobilome composition for West Siberian agricultural soils. <b>Methods:</b> Twelve composite soil samples were collected from agroecosystems under seven crop types across diverse soil types in southern West Siberia (September 2022). Shotgun metagenomics was performed on an Illumina NovaSeq 6000 platform. Taxonomic profiling used Kraken2/Bracken; ARG annotation used Prokka/DeepARG (identity ≥ 70%, probability score ≥ 0.8); while MGE characterization used Platon, HMMER v3.3.2, and Prokka-based integrase annotation. Resistome load was normalized to the single-copy housekeeping gene <i>rpoB</i>; ARG-MGE associations were defined as co-localization within 10 kb on the same contig. <b>Results:</b> Microbial communities were dominated by <i>Pseudomonadota</i> and <i>Bacillota</i>, with a stable core of <i>Streptomycetaceae</i>, <i>Nitrobacteraceae</i>, and <i>Sphingomonadaceae</i>. Normalized resistome load (N/<i>rpoB</i> 2.30-5.37) indicated moderate anthropogenic pressure. Dominant ARGs included efflux pumps (<i>emrA</i>, <i>drrA</i>, <i>tetA</i>, <i>bcr</i>, <i>fsr</i>), target modification (<i>lnrL</i>), and lipid A modification (<i>arnA</i>) genes. Class 1 integron integrase (<i>intI1</i>/<i>rpoB</i> 0.64-1.59) was detected in all 12 samples, exceeding unity in 9 of 12. ARG-MGE co-localizations were found in 11 of 12 samples. In sample Mg_155, genes <i>emrA-emrB</i> and <i>bcr</i> (NODE_16) and <i>arnA</i> and <i>lnrL</i> (NODE_6) were each independently associated with distinct prophage <i>IntA</i> integrase copies within <i>Pseudomonas</i> contigs, documenting multiple parallel horizontal transfer events encompassing resistance to five antibiotic classes. <b>Conclusions:</b> This work establishes the first metagenomic baseline of resistome and mobilome for West Siberian agroecosystems. The obtained data indicate moderate anthropogenic pressure on soil microbiomes, consistent with temperate agricultural systems with limited organic fertilizer input. The detected ARG-MGE co-localizations and evidence of prophage-mediated transfer of resistance determinants beyond their natural hosts suggest that mobilization potential in the region warrants consideration in future AMR monitoring programs.', 2026, 'europepmc', '{"authorString": "Skotareva AE, Sokolova EA, Voronina EN.", "journal": null}'::jsonb),
  ('bb3d825a-4f86-5404-ba61-e1d22dbd6045', '41597740', '10.3390/microorganisms14010222', 'Metals and Microbes: Microbial Community Diversity and Antibiotic Resistance in the Animas River Watershed, Colorado, USA', 'Antimicrobial resistant (AMR) infections are a persistent public health issue causing excess death and economic impacts globally. Because AMR in clinical settings is often acquired from nonpathogenic bacteria that surround us, environmental surveillance must be better characterized. It has been well established that metals can co-select for bacterial AMR. Furthermore, recent studies have shown that compromised microbial community diversity may lead to community invasion by antibiotic resistance genes (ARGs). Widespread legacy mining has led to acid mine drainage and metal contamination of waterways and sediments throughout the western United States, potentially compromising microbial community diversity while simultaneously selecting for AMR bacteria. Our study objectives were to survey metal contaminated sediments from the Bonita Peak Mining District (BPMD) in southwestern Colorado, USA, compared to sites downstream in Durango, CO for bacterial and ARG diversity. Sediment bacteria were characterized using 16S rRNA Ilumina and metagenomic sequencing. We found that overall, bacterial diversity was lower in metal-contaminated, acidic sites (<i>p</i> = 0.04). Metagenomic sequencing revealed 31 different ARGs, with those encoding for efflux pumps (<i>mex</i> and <i>spe</i> gene families) substantially more prevalent in the BPMD sites, elucidating a specific AMR marker fingerprint from the high metal concentration sediments. Raising awareness and providing antimicrobial tracking techniques to resource limited communities could help provide information needed for better antibiotic use recommendations and environmental monitoring.', 2026, 'europepmc', '{"authorString": "Lowell JL, Brown L.", "journal": null}'::jsonb),
  ('4b6ea7f8-db82-5022-9513-3473f16a7eb9', '42091727', '10.1007/s00253-026-13775-4', 'Motility and growth Burkholderia two-component: a new regulatory system of Burkholderia seminalis', 'The two-component regulatory system (TCS) is a highly conserved global signal transduction mechanism that enables microorganisms to adapt to changing environments in response to signals. Burkholderia seminalis TC3.4.2R3 has attracted attention as a potential phytopathogenic biological control agent. In this study, a TCS mutant was obtained and evaluated in comparison to wild type using different approaches. The transcriptome analysis revealed 374 differentially expressed genes, some of which are involved in motility and chemotaxis (downregulated) and related to iron uptake and pyochelin production (upregulated). Swarming and swimming motility were impaired in the mutant, while biofilm production increased, leading to differences in growth profiles. However, the biocontrol efficacy was similar. These findings suggest that the new TCS, named motility and growth Burkholderia two-component regulator (MgbTC), positively regulates motility and chemotaxis genes while negatively controlling genes related to biofilm production, iron uptake and pyochelin siderophore production in the Burkholderia seminalis TC3.4.2R3. KEY POINTS: • The new motility and growth of Burkholderia two-component regulator (MgbTC) system • MgbTC positively regulates motility and chemotaxis genes in B. seminalis TC3.4.2R3 • MgbTC negatively controls iron uptake and pyochelin and biofilm production genes.', 2026, 'europepmc', '{"authorString": "Cardinali-Rezende J, Silva CAPT, Costa A, Garrido LM, Ferro M, Bacci M, De Souza AO, Ara\u00fajo WL.", "journal": null}'::jsonb),
  ('0d886f89-cb57-5abe-94d3-28e0cb6f2f26', '42197330', '10.3390/microorganisms14050943', 'Analysis of Putative CzcR Targets Under Zinc Sufficiency and Zinc Excess Conditions in &lt;i&gt;Pseudomonas aeruginosa&lt;/i&gt; Using ChIP-Seq', '<i>Pseudomonas aeruginosa</i> is a versatile opportunistic pathogen that thrives in hostile environments by tightly regulating zinc (Zn) homeostasis. The CzcRS two-component system is pivotal for Zn resistance, primarily by activating the CzcCBA efflux pump, yet its basal activity and full regulon remain poorly defined. Here, we analyzed putative CzcR targets under zinc sufficiency (ZS) and zinc excess (ZE) conditions in <i>P. aeruginosa</i> PAO1 using ChIP-seq. Under ZE, we identified 32 CzcR binding sites, potentially regulating 39 genes, many of which are linked to virulence, antibiotic resistance, and stress response. Under ZS, 10 binding sites were detected, revealing distinct CzcR targets. Considering the presence of a CzcR binding motif close to the peaks summit and RNA-seq data, we identified seven and four novel CzcR-regulated genes under ZE and ZS conditions, respectively, mostly implicated in bacterial virulence. Our findings highlight that CzcR may exhibit different functionalities depending on Zn concentration: its basal activity maintains physiological robustness, while its activated form orchestrates Zn detoxification and virulence modulation. This study expands our understanding of how <i>P. aeruginosa</i> integrates metal sensing with clinically relevant phenotypes, highlighting CzcR as a key regulator at the intersection of metal homeostasis and pathogenicity.', 2026, 'europepmc', '{"authorString": "Mauffrey F, Ducret V, Milho CG, Perron K.", "journal": null}'::jsonb),
  ('6bd5a47a-ef38-53b1-9b45-ad0fbc908ad3', '41738901', '10.1128/jb.00471-25', 'Contribution of two-component regulatory systems to the acute-to-chronic infection transition of &lt;i&gt;Pseudomonas aeruginosa&lt;/i&gt; in cystic fibrosis', 'Cystic fibrosis (CF) is a life-threatening genetic disorder that causes severe dysfunction in the lungs, digestive system, and other organs. Chronic respiratory infections are a significant cause of morbidity and mortality among CF-related complications. <i>Pseudomonas aeruginosa</i> is an opportunistic bacterial pathogen and a predominant colonizer of the CF lung. It drives a progressive decline in pulmonary function. This pathogen shows remarkable adaptability. It can establish both acute and chronic infections despite the host''s immune defenses and antimicrobial treatments. <i>P. aeruginosa</i> expresses a diverse set of virulence factors, including adhesins, proteases, exotoxins, siderophores, secretion systems, and exopolysaccharides. These factors facilitate host colonization, immune evasion, and disease progression. The transition from acute to chronic infection is mediated by bacterial sensing of environmental signals. These signals dynamically modulate the expression of virulence factors. Also, the hostile conditions within the CF lung drive the acquisition and accumulation of adaptive mutations in the bacterial genome. These genetic modifications often impair the efficiency of DNA repair mechanisms, leading to a hypermutable phenotype. This accelerates bacterial evolution. As a result, acute-phase virulence factors are downregulated, while antimicrobial resistance and biofilm formation increase. This contributes to persistent and refractory infections. In this review, we examine the crucial roles of two-component regulatory systems. These systems fine-tune gene expression, enhance bacterial survival, and regulate the shift from acute to chronic infection. Understanding these adaptive mechanisms is essential for developing novel therapeutic strategies to combat this highly resilient pathogen.', 2026, 'europepmc', '{"authorString": "Flores-Vega VR, Hern\u00e1ndez-Mart\u00ednez G, Cocotl-Ya\u00f1ez M, Ares MA, Lincopan N, Ortiz-Navarrete V, Rosales-Reyes R.", "journal": null}'::jsonb),
  ('27c7dd84-192c-57b7-85d0-6ab88e5b3a97', '42144257', '10.1111/1462-2920.70329', 'ActJK Signal Transduction System Contributes to Copper and Zinc Resistance in Sinorhizobium meliloti', 'Two-component systems (TCS) play a vital role in bacterial adaptation to environmental stresses, including acid and metal toxicity. The ActJK system has been previously identified as a key regulator of acid tolerance in Sinorhizobium meliloti, a model organism for studying rhizobia-legume symbioses. Here, we expand the functional scope of ActJK, demonstrating its involvement in responses to copper and zinc stress. Using transcriptional fusion assays, we observed the ActJK''s operon activation through degP1''s upstream promoter region induction by Cu<sup>2+</sup> and Zn<sup>2+</sup> in a dose-dependent manner, a response absent in the ΔactJ mutant. Comparative proteomic analysis revealed distinct yet related overlapping regulatory pathways under Cu<sup>2+</sup> and Zn<sup>2+</sup> stress, with differentially expressed proteins suggesting convergence in efflux pump regulation and stress response mechanisms. The ΔactJ mutant displayed reduced tolerance to metal stress, impaired expression of metal detoxification genes, and altered antibiotic susceptibility profiles. Together, these findings highlight the intricate interplay between metal resistance and multidrug efflux systems in S. meliloti and underscore ActJK as a vital regulator integrating responses to environmental fluctuations. Understanding these regulatory mechanisms enhances our knowledge of bacterial survival in soil and rhizosphere under abiotic stress conditions and offers potential applications for optimising agricultural inoculants for acidic and metal-contaminated soils.', 2026, 'europepmc', '{"authorString": "Vacca C, Belhart K, Cafiero JH, P\u00e9rez A, Bolzan MM, Heredia JB, Ca\u00f1ameras P, Draghi W, Lagares A, Niehaus K, Del Papa MF.", "journal": null}'::jsonb),
  ('a14d7452-517b-57b4-8059-487f07db6655', '42197417', '10.3390/microorganisms14051031', 'Functional Characterization of the Histidine Kinase BaeS Reveals Critical Residues for BaeSR-Dependent Stress Signaling in &lt;i&gt;Escherichia coli&lt;/i&gt;', '<i>Escherichia coli</i>, a facultative anaerobic Gram-negative member of the Enterobacteriaceae, is an increasingly important opportunistic pathogen driven in part by rising resistance to clinically important antibiotics. Regulation of multidrug efflux systems by two-component signal transduction pathways, particularly the BaeSR system, plays a central role in this process. However, the functional residues governing signal transduction through the sensor kinase BaeS remain incompletely defined. In this study, we integrated domain prediction, homology-guided site-directed mutagenesis, in vitro protein purification, autophosphorylation assays, and reverse-transcription quantitative polymerase chain reaction (RT-qPCR)-based transcriptional analysis of selected BaeSR-regulated genes to delineate key residues required for BaeS function. Sequence analysis identified His250 as a candidate autophosphorylation site and Asn364 as a conserved residue within the catalytic domain. Biochemical characterization of purified wild-type BaeS and an H250A mutant demonstrated that His250 is indispensable for autophosphorylation. Consistently, RT-qPCR analysis showed that BaeS activation markedly induced the transcription of BaeSR-regulated efflux-associated genes, whereas genetic deletion of <i>baeS</i> or selective disruption of kinase activity by the N364A mutation abolished this response. Together, these findings establish His250 as a key residue for BaeS autophosphorylation and identify Asn364 as essential for inducible BaeSR signaling and activation of resistance-associated target genes, thereby establishing an experimental framework for elucidating BaeSR-mediated efflux regulation and informing future studies of resistance regulatory networks and potential intervention strategies centered on key signaling nodes.', 2026, 'europepmc', '{"authorString": "Chen S, Qi Z, Wang L, Wu L, Xie J, Ma R, Zhang K, Ji T, Zhou M, Zheng L, Fu QB.", "journal": null}'::jsonb),
  ('4058d3c8-5393-514a-b6db-54f4d56ea110', '41460375', '10.1007/s11033-025-11372-8', 'The PhoPQ two-component regulatory system as an important regulator of bacterial stress response', 'Two-component regulatory systems (TCSs) are fundamental regulatory mechanisms that enable bacteria to detect and respond to a wide range of environmental signals. Each TCS typically consists of two proteins: a membrane-associated histidine kinase that acts as a sensor, and a cytoplasmic response regulator that mediates transcriptional changes. This design allows TCSs to enable bacteria to precisely regulate their physiology and adapt to changing environmental conditions. Among these systems, PhoPQ is one of the better characterised examples, particularly in Gram-negative pathogens. The PhoPQ system responds to environmental signals such as cationic antimicrobial peptides, low pH, and changes in metal ion concentrations (e.g., Mg²⁺, Ca²⁺, Fe³⁺). Activation of PhoPQ initiates the regulation of many downstream genes, including those responsible for lipid A modification, which in turn contributes to bacterial resistance to polymyxin B. A growing body of evidence points to the key role of PhoPQ in the virulence and survival of many Gram-negative bacteria. This makes PhoPQ not only an important element of bacterial pathogenicity, but also a promising therapeutic target for the development of new pharmacological strategies.', 2025, 'europepmc', '{"authorString": "Omelaniuk AM, Gmiter D, Kaca W.", "journal": null}'::jsonb),
  ('a80f16ff-1fec-535a-a630-4c7288d9cf53', '41744904', '10.1128/msphere.00744-25', 'The IrlS2-IrlR2 two-component system is a global regulator of biofilm formation, stress adaptation, and virulence in &lt;i&gt;Burkholderia pseudomallei&lt;/i&gt;', '<i>Burkholderia pseudomallei</i>, which causes melioidosis, is an adaptable pathogen that survives in diverse environments. Two-component systems (TCSs) play pivotal roles in bacterial signal transduction and adaptation, yet the functions of most TCSs in <i>B. pseudomallei</i> remain poorly characterized. Here, we identified and functionally characterized a previously unstudied TCS, IrlS2-IrlR2, which shares partial homology with the IrlS-IrlR system but exhibits distinct regulatory roles. Knockout of <i>irlR2</i> (Δ<i>irlR2</i>) did not affect growth in nutrient-rich medium but led to enhanced biofilm formation, reduced motility, decreased siderophore production, and increased sensitivity to oxidative stress, all of which were restored in the complemented strain. The mutant also exhibited growth retardation under subinhibitory cobalt concentrations, despite unchanged MICs. In infection assays, Δ<i>irlR2</i> displayed impaired adhesion and cytotoxicity toward A549 cells and attenuated virulence in <i>Galleria mellonella</i>, with a higher median lethal dose than the wild type. Transcriptomic analysis revealed <i>hcp2</i> within the type VI secretion system 2 (T6SS-2) cluster, and multiple T3SS-3 genes were strongly downregulated, consistent with reduced intracellular survival, whereas T3SS-1 and T3SS-2 were upregulated, suggesting a dysregulated secretion system balance. Adhesion-related (<i>fimA</i>) and iron transport (<i>fhuBCDF</i>) genes were repressed, while oxidative stress-associated (<i>cydABX</i>) and nitrate reductase (<i>narIJHGK-nasA</i>) operons were induced, indicating altered regulation of iron homeostasis, redox balance, and nitrogen metabolism, which may reflect adaptive responses to environmental stress. Collectively, these results demonstrate that the IrlS2-IrlR2 system functions as a global regulator, integrating biofilm formation, stress adaptation, and virulence regulation, highlighting its role in the environmental resilience and pathogenic potential of <i>B. pseudomallei</i>.<h4>Importance</h4><i>Burkholderia pseudomallei</i>, which causes melioidosis, poses a serious threat to human and animal health in tropical and subtropical regions worldwide. Classified as a tier 1 biothreat agent by the U.S. CDC and a category II pathogen in China, <i>B. pseudomallei</i> causes severe pneumonia and septicemia with case-fatality rates approaching 50%. Despite its medical and epidemiological significance, the regulatory mechanisms controlling its virulence and environmental persistence remain poorly understood. This study identifies IrlS2-IrlR2 as a previously uncharacterized two-component system (TCS) that acts as a global regulator integrating biofilm formation, stress adaptation, and virulence. Functional and transcriptomic analyses reveal that IrlS2-IrlR2 modulates secretion systems, iron homeostasis, and redox balance. These findings deepen our understanding of <i>B. pseudomallei</i> pathogenesis and highlight the role of TCS-mediated regulatory networks.', 2026, 'europepmc', '{"authorString": "Chen F, Luo J, Wang Y, Tian S, Kang X, Zhang N, Zheng W, Li W, Xia Q, Kuang D.", "journal": null}'::jsonb),
  ('b21c6efa-f0a0-5d12-9fab-a228a97e6e4b', '41684740', '10.1099/acmi.0.001029.v3', 'Genomic screening of eight antibiotic-resistant Pseudomonas isolated from rainbow trout (Oncorhynchus mykiss)', 'Open aquaculture systems represent a strategic environment for the study of antibiotic resistance dynamics, given the interactions between bacteria from humans, animals and the environment. The genomic investigation of eight <i>Pseudomonas</i> isolated from rainbow trout in a previous study demonstrated that non-wild-type and resistance phenotypes to several antibiotics (oxytetracycline, sulphonamides and florfenicol) were predominantly attributable to the presence of related genes [<i>tet(Y)</i>, <i>sul2</i> and <i>floR</i>]. Phylogenetic analyses revealed that several species of <i>Pseudomonas iridis</i> harboured these genes on mobile genetic elements, including integrative conjugative elements (ICE) on the chromosome or plasmids with a high degree of sequence similarity (>99%) between the genetic structures. Furthermore, comparisons between isolates with low and high MIC values to colistin showed mutations in the amino acid sequences of the PhoP/Q two-component system and a lack of the pmrA/B system. A wide diversity of known LPS-modifying genes involved in colistin resistance was also detected in resistant isolates. This study provided insights into the dynamics of antibiotic resistance in aquaculture systems. It demonstrated the presence of genes located on an ICE inserted into a chromosome or plasmid in <i>P. iridis</i>, which was isolated from healthy rainbow trout in different farms within the same watershed. Our study raises questions about the ability of environmental <i>Pseudomonas</i> bacteria to spread their antibiotic resistance genes to other bacterial species that are of interest in terms of human or animal surveillance.', 2026, 'europepmc', '{"authorString": "Oberl\u00e9 K, Bednarek G, Rispe C, Calvez S.", "journal": null}'::jsonb)
