  ('ae2acb32-0a1c-5940-92fa-efa929e19af7', 'gene', '6fdc2a04-349b-51da-afbe-a7027e7978f6', 'implicates', 'gene', NULL, 'acrAB', '41954976', 'CARD', 'ARO:3000823', 0.975, 'ai/extraction.py@claude-sonnet-5', TRUE, '{"subject": "Rob", "object_kind": "gene", "evidence_span": "other AraC/XylS family transcriptional activators, MarA, SoxS, or Rob, induced fewer signals", "gene_symbol": "AraC/MarA-family activator", "gene_locus": "A8H40_RS24275", "verdict_reason": "CARD states RamA is a positive regulator of AcrAB-TolC, directly implicating it."}'::jsonb),
